    description: 'Understanding what it means to trust God when the path is unclear.',
    datePreached: '2023-11-12',
    fileUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3',
    thumbnailUrl: 'https://picsum.photos/seed/sermon3/800/600',
    duration: '38:45',
    playCount: 980,
    downloadCount: 320,
    createdAt: new Date().toISOString()
  }
];

export const db = {
  getMedia: (): Media[] => {
    const data = localStorage.getItem(MEDIA_KEY);
    if (!data) {
      localStorage.setItem(MEDIA_KEY, JSON.stringify(DEFAULT_MEDIA));
      return DEFAULT_MEDIA;
    }
    return JSON.parse(data);
  },

  saveMedia: (media: Media[]) => {
    localStorage.setItem(MEDIA_KEY, JSON.stringify(media));
  },

  addMedia: (item: Omit<Media, 'id' | 'playCount' | 'downloadCount' | 'createdAt'>) => {
    const current = db.getMedia();
    const newItem: Media = {
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      playCount: 0,
      downloadCount: 0,
      createdAt: new Date().toISOString()
    };
    db.saveMedia([newItem, ...current]);
    return newItem;
  },

  updateMedia: (id: string, updates: Partial<Media>) => {
    const current = db.getMedia();
    const updated = current.map(m => m.id === id ? { ...m, ...updates } : m);
    db.saveMedia(updated);
  },

  deleteMedia: (id: string) => {
    const current = db.getMedia();
    db.saveMedia(current.filter(m => m.id !== id));
  },

  incrementPlay: (id: string) => {
    const current = db.getMedia();
    const updated = current.map(m => m.id === id ? { ...m, playCount: m.playCount + 1 } : m);
    db.saveMedia(updated);
  },

  incrementDownload: (id: string) => {
    const current = db.getMedia();
    const updated = current.map(m => m.id === id ? { ...m, downloadCount: m.downloadCount + 1 } : m);
    db.saveMedia(updated);
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  async generateMediaMetadata(description: string) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Given this church message description: "${description}", suggest a catchy spiritual title and 3 relevant tags.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              suggestedTitle: { type: Type.STRING },
              tags: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["suggestedTitle", "tags"]
          }
        }
      });
      return JSON.parse(response.text);
    } catch (error) {
      console.error("Gemini Error:", error);
      return null;
    }
  }
};

