import React from 'react';
import { Play, Pause, SkipBack, SkipForward, Volume2, Download, X } from 'lucide-react';
import { Media } from '../types';
import { db } from '../services/db';

interface AudioPlayerProps {
  media: Media | null;
  onClose: () => void;
}

const AudioPlayer: React.FC<AudioPlayerProps> = ({ media, onClose }) => {
  const [isPlaying, setIsPlaying] = React.useState(false);
  const [progress, setProgress] = React.useState(0);
  const [volume, setVolume] = React.useState(80);
  const audioRef = React.useRef<HTMLAudioElement | null>(null);

  React.useEffect(() => {
    if (media) {
      setIsPlaying(true);
      db.incrementPlay(media.id);
      if (audioRef.current) {
        audioRef.current.play();
      }
    }
  }, [media]);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) audioRef.current.pause();
      else audioRef.current.play();
      setIsPlaying(!isPlaying);
    }
  };

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      const p = (audioRef.current.currentTime / audioRef.current.duration) * 100;
      setProgress(p || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (audioRef.current) {
      const newTime = (parseFloat(e.target.value) / 100) * audioRef.current.duration;
      audioRef.current.currentTime = newTime;
      setProgress(parseFloat(e.target.value));
    }
  };

  const handleDownload = () => {
    if (media) {
      db.incrementDownload(media.id);
      const link = document.createElement('a');
      link.href = media.fileUrl;
      link.download = `${media.title}.mp3`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  if (!media) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 shadow-2xl z-[100] transform transition-transform duration-300">
      <audio
        ref={audioRef}
        src={media.fileUrl}
        onTimeUpdate={handleTimeUpdate}
        onEnded={() => setIsPlaying(false)}
      />

      <div className="max-w-7xl mx-auto px-4 py-3 flex flex-col md:flex-row items-center justify-between gap-4">
        {/* Media Info */}
        <div className="flex items-center space-x-4 w-full md:w-1/4">
          <img
            src={media.thumbnailUrl}
            alt={media.title}
            className="w-12 h-12 rounded-lg object-cover shadow-sm"
          />
          <div className="overflow-hidden">
            <h4 className="text-sm font-bold text-slate-900 truncate">{media.title}</h4>
            <p className="text-xs text-slate-500 truncate">{media.preacher}</p>
          </div>
          <button onClick={onClose} className="md:hidden ml-auto p-1 text-slate-400">
            <X className="h-5 w-5" />
          </button>
        </div>

        {/* Controls */}
        <div className="flex flex-col items-center w-full md:w-1/2 gap-2">
          <div className="flex items-center space-x-6">
            <button className="text-slate-400 hover:text-indigo-600 transition-colors">
              <SkipBack className="h-5 w-5" />
            </button>
            <button
              onClick={togglePlay}
              className="bg-indigo-600 text-white p-3 rounded-full hover:bg-indigo-700 transition-colors shadow-lg"
            >
              {isPlaying ? <Pause className="h-6 w-6 fill-current" /> : <Play className="h-6 w-6 fill-current ml-0.5" />}
            </button>
            <button className="text-slate-400 hover:text-indigo-600 transition-colors">
              <SkipForward className="h-5 w-5" />
            </button>
          </div>
          <div className="w-full flex items-center space-x-3">
            <span className="text-[10px] text-slate-400 w-8">
              {audioRef.current ? formatTime(audioRef.current.currentTime) : '0:00'}
            </span>
            <input
              type="range"
              min="0"
              max="100"
              step="0.1"
              value={progress}
              onChange={handleSeek}
              className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
            />
            <span className="text-[10px] text-slate-400 w-8">
              {media.duration}
            </span>
          </div>
        </div>

        {/* Tools */}
        <div className="hidden md:flex items-center justify-end space-x-4 w-1/4">
          <div className="flex items-center space-x-2">
            <Volume2 className="h-4 w-4 text-slate-400" />
            <input
              type="range"
              min="0"
              max="100"
              value={volume}
              onChange={(e) => {
                const v = parseInt(e.target.value);
                setVolume(v);
                if (audioRef.current) audioRef.current.volume = v / 100;
              }}
              className="w-20 h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
            />
          </div>
          <button
            onClick={handleDownload}
            className="flex items-center space-x-1 text-xs font-semibold text-slate-600 hover:text-indigo-600 bg-slate-50 hover:bg-indigo-50 px-3 py-1.5 rounded-full border border-slate-200 transition-all"
          >
            <Download className="h-3.5 w-3.5" />
            <span>MP3</span>
          </button>
          <button onClick={onClose} className="p-1 text-slate-400 hover:text-slate-600 transition-colors">
            <X className="h-5 w-5" />
          </button>
        </div>
      </div>
    </div>
  );
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

export default AudioPlayer;

import React from 'react';
import { Search, Filter, Play, Download, Calendar, User, SlidersHorizontal } from 'lucide-react';
import { db } from '../services/db';
import { Media, Category } from '../types';

interface LibraryProps {
  onPlay: (media: Media) => void;
}

const Library: React.FC<LibraryProps> = ({ onPlay }) => {
  const [allMedia, setAllMedia] = React.useState<Media[]>([]);
  const [filteredMedia, setFilteredMedia] = React.useState<Media[]>([]);
  const [searchQuery, setSearchQuery] = React.useState('');
  const [selectedCategory, setSelectedCategory] = React.useState<string>('All');

  React.useEffect(() => {
    const data = db.getMedia();
    setAllMedia(data);
    setFilteredMedia(data);
  }, []);

  React.useEffect(() => {
    let result = allMedia;

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(m => 
        m.title.toLowerCase().includes(q) || 
        m.preacher.toLowerCase().includes(q) ||
        m.description?.toLowerCase().includes(q)
      );
    }

    if (selectedCategory !== 'All') {
      result = result.filter(m => m.category === selectedCategory);
    }

    setFilteredMedia(result);
  }, [searchQuery, selectedCategory, allMedia]);

  const handleDownload = (e: React.MouseEvent, media: Media) => {
    e.stopPropagation();
    db.incrementDownload(media.id);
    const link = document.createElement('a');
    link.href = media.fileUrl;
    link.download = `${media.title}.mp3`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
          <h1 className="text-4xl font-bold text-slate-900">Media Library</h1>
          <p className="text-slate-500 text-lg">Browse through our complete collection of spiritual content.</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <div className="relative flex-grow sm:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
            <input
              type="text"
              placeholder="Search title, preacher..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none text-slate-900"
            />
          </div>
          <div className="relative">
            <SlidersHorizontal className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
            <select
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
              className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none text-slate-900 font-medium"
            >
              <option value="All">All Categories</option>
              {Object.values(Category).map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
            <Filter className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none" />
          </div>
        </div>
      </div>

      {filteredMedia.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredMedia.map((media) => (
            <div 
              key={media.id} 
              className="group bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-xl transition-all duration-300 overflow-hidden"
              onClick={() => onPlay(media)}
            >
              <div className="relative aspect-[4/3] overflow-hidden cursor-pointer">
                <img
                  src={media.thumbnailUrl}
                  alt={media.title}
                  className="w-full h-full object-cover transform transition-transform group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <div className="bg-white/90 backdrop-blur-sm p-4 rounded-full text-indigo-600 shadow-lg transform scale-90 group-hover:scale-100 transition-transform">
                    <Play className="h-6 w-6 fill-current" />
                  </div>
                </div>
                <div className="absolute top-2 right-2 bg-black/60 backdrop-blur-md text-white text-[10px] px-2 py-1 rounded-md font-bold">
                  {media.duration}
                </div>
                <div className="absolute bottom-3 left-3 bg-indigo-600 text-white text-[10px] uppercase tracking-wider px-2 py-1 rounded font-bold">
                  {media.category}
                </div>
              </div>

              <div className="p-5 space-y-4">
                <div className="space-y-1">
                  <h3 className="text-lg font-bold text-slate-900 group-hover:text-indigo-600 transition-colors line-clamp-1">
                    {media.title}
                  </h3>
                  <div className="flex flex-col space-y-1 text-xs text-slate-500">
                    <div className="flex items-center">
                      <User className="h-3 w-3 mr-1.5" />
                      {media.preacher}
                    </div>
                    <div className="flex items-center">
                      <Calendar className="h-3 w-3 mr-1.5" />
                      {new Date(media.datePreached).toLocaleDateString()}
                    </div>
                  </div>
                </div>

                <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                  <div className="flex items-center space-x-3 text-[10px] font-bold text-slate-400">
                    <span>{media.playCount.toLocaleString()} Plays</span>
                    <span>•</span>
                    <span>{media.downloadCount.toLocaleString()} DLs</span>
                  </div>
                  <button
                    onClick={(e) => handleDownload(e, media)}
                    className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    title="Download MP3"
                  >
                    <Download className="h-5 w-5" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="py-32 text-center bg-white rounded-3xl border border-dashed border-slate-300">
          <div className="max-w-xs mx-auto space-y-4">
            <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
              <Search className="h-10 w-10 text-slate-300" />
            </div>
            <h3 className="text-xl font-bold text-slate-900">No matches found</h3>
            <p className="text-slate-500">We couldn't find any media matching your current filters. Try adjusting your search.</p>
            <button
              onClick={() => { setSearchQuery(''); setSelectedCategory('All'); }}
              className="text-indigo-600 font-bold hover:underline"
            >
              Clear all filters
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Library;

