                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({...errors, title: undefined});
                      }}
                      placeholder="e.g. The Power of Grace"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.title ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Preacher</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({...errors, preacher: undefined});
                      }}
                      placeholder="e.g. Pastor James"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.preacher ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      {Object.values(Category).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Date Preached</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({...errors, datePreached: undefined});
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.datePreached ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.datePreached && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.datePreached}</p>}
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase">Description (Optional)</label>
                  <textarea
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Briefly describe the message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase">Media File (MP3)</label>
                  <div className={`p-4 bg-slate-50 border rounded-2xl flex flex-col gap-3 transition-all ${
                    errors.fileUrl ? 'border-red-500 bg-red-50/30' : 'border-slate-200'
                  }`}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-3">
                        <div className={`p-2 rounded-lg transition-colors ${formData.fileUrl ? 'bg-green-100 text-green-600' : errors.fileUrl ? 'bg-red-100 text-red-600' : 'bg-indigo-100 text-indigo-600'}`}>
                          {isUploadingFile ? <Loader2 className="h-5 w-5 animate-spin" /> : <Upload className="h-5 w-5" />}
                        </div>
                        <div>
                          <p className={`text-sm font-bold ${errors.fileUrl ? 'text-red-700' : 'text-slate-900'}`}>
                            {isUploadingFile ? 'Uploading...' : formData.fileUrl ? 'Audio ready' : 'Choose audio file'}
                          </p>
                          <p className="text-xs text-slate-500">MP3 format only</p>
                        </div>
                      </div>

                      {!isUploadingFile && (
                        <>
                          <input
                            type="file"
                            accept="audio/mpeg"
                            onChange={handleFileChange}
                            className="hidden"
                            id="audio-upload"
                          />
                          <label
                            htmlFor="audio-upload"
                            className="cursor-pointer text-xs font-bold text-indigo-600 bg-white border border-indigo-100 px-3 py-1.5 rounded-lg shadow-sm hover:bg-indigo-50 transition-colors"
                          >
                            {formData.fileUrl ? 'Replace' : 'Browse'}
                          </label>
                        </>
                      )}
                    </div>

                    {(isUploadingFile || (uploadProgress > 0 && !editingId)) && (
                      <div className="space-y-1.5">
                        <div className="flex items-center justify-between text-[10px] font-bold">
                          <span className={`${uploadProgress === 100 ? 'text-green-600 flex items-center gap-1' : 'text-indigo-600'}`}>
                            {uploadProgress === 100 && <CheckCircle className="h-3 w-3" />}
                            {uploadProgress === 100 ? 'Complete' : 'Uploading...'}
                          </span>
                          <span className="text-slate-400">{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                          <div 
                            className={`h-full transition-all duration-300 rounded-full ${uploadProgress === 100 ? 'bg-green-500' : 'bg-indigo-600 animate-pulse'}`}
                            style={{ width: `${uploadProgress}%` }}
                          />
                        </div>
                      </div>
                    )}
                    {errors.fileUrl && !isUploadingFile && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1"><AlertCircle className="h-3 w-3" /> {errors.fileUrl}</p>}
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button
                  type="button"
                  onClick={closeModal}
                  className="flex-grow py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-all"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={isUploadingFile}
                  className="flex-grow-[2] py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50 disabled:shadow-none"
                >
                  {editingId ? 'Save Changes' : 'Publish Content'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, Info, X, AlertCircle } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
}

const AdminDashboard: React.FC = () => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: 'https://picsum.photos/seed/new/800/600',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "Title is required";
    else if (formData.title.length < 3) newErrors.title = "Title must be at least 3 characters";

    if (!formData.preacher.trim()) newErrors.preacher = "Preacher/Speaker is required";

    if (!formData.datePreached) newErrors.datePreached = "Date is required";

    if (!formData.fileUrl) newErrors.fileUrl = "An audio file must be uploaded";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this media?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return alert("Please enter a description first.");
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsUploadingFile(true);
      setUploadProgress(0);
      setShowSuccess(false);
      setErrors(prev => ({ ...prev, fileUrl: undefined }));

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 25;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 200);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage your church's digital media assets.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Upload New Media</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Total Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
          <h2 className="font-bold text-slate-900">Recent Uploads</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50">
                <th className="px-6 py-4">Title</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 text-center">Stats</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <img src={media.thumbnailUrl} alt="" className="w-10 h-10 rounded-lg object-cover" />
                      <span className="font-bold text-slate-900">{media.title}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">{media.preacher}</td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2.5 py-1 rounded-full text-[10px] font-bold bg-indigo-50 text-indigo-600 uppercase">
                      {media.category}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col text-center text-xs font-medium text-slate-500">
                      <span>{media.playCount} plays</span>
                      <span>{media.downloadCount} dl</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">{new Date(media.datePreached).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                        title="Edit Details"
                      >
                        <Edit3 className="h-5 w-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                        title="Delete Media"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit Media Details' : 'Upload New Media'}</h3>
                <p className="text-xs text-slate-500 mt-0.5">Maintain your digital sanctuary by updating content.</p>
              </div>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto custom-scrollbar">
              <div className="space-y-4">
                <div className="bg-indigo-50 p-4 rounded-2xl border border-indigo-100 flex gap-4">
                  <div className="bg-indigo-600 p-2 rounded-lg h-fit shadow-md">
                    <Sparkles className="h-5 w-5 text-white" />
                  </div>
                  <div className="flex-grow">
                    <p className="text-sm font-bold text-indigo-900">FaithStream AI Assistant</p>
                    <p className="text-xs text-indigo-700 mb-3">Tell me about the message below and I'll help you refine the title.</p>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !formData.description}
                      className="text-xs font-bold bg-indigo-600 text-white px-3 py-1.5 rounded-lg disabled:opacity-50 flex items-center gap-2 transition-all hover:bg-indigo-700 active:scale-95"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      Refine Title
                    </button>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({...errors, title: undefined});
                      }}
                      placeholder="e.g. The Power of Grace"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.title ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Preacher / Speaker</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({...errors, preacher: undefined});
                      }}
                      placeholder="e.g. Pastor John Doe"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.preacher ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      {Object.values(Category).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Date Preached</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({...errors, datePreached: undefined});
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.datePreached ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.datePreached && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.datePreached}</p>}
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Description</label>
                  <textarea
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Briefly describe the theme of the message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Media File (MP3)</label>
                  <div className={`p-4 border rounded-2xl flex flex-col gap-4 transition-all ${
                    errors.fileUrl ? 'border-red-500 bg-red-50/30' : 
                    showSuccess ? 'border-green-300 bg-green-50/30' : 'bg-slate-50 border-slate-200'
                  }`}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-3">
                        <div className={`p-2.5 rounded-xl transition-all shadow-sm ${
                          showSuccess ? 'bg-green-600 text-white' : 
                          errors.fileUrl ? 'bg-red-600 text-white' : 
                          isUploadingFile ? 'bg-indigo-600 text-white animate-pulse' : 'bg-white border border-slate-200 text-indigo-600'
                        }`}>
                          {isUploadingFile ? <Loader2 className="h-5 w-5 animate-spin" /> : 
                           showSuccess ? <CheckCircle className="h-5 w-5" /> :
                           <Upload className="h-5 w-5" />}
                        </div>
                        <div>
                          <p className={`text-sm font-bold transition-colors ${
                            showSuccess ? 'text-green-700' : 
                            errors.fileUrl ? 'text-red-700' : 'text-slate-900'
                          }`}>
                            {isUploadingFile ? 'Uploading message...' : 
                             showSuccess ? 'Upload complete!' : 
                             'Select audio file'}
                          </p>
                          <p className="text-[11px] text-slate-500 font-medium">MP3 Format • Up to 100MB</p>
                        </div>
                      </div>

                      {!isUploadingFile && (
                        <>
                          <input
                            type="file"
                            accept="audio/mpeg"
                            onChange={handleFileChange}
                            className="hidden"
                            id="audio-upload"
                          />
                          <label
                            htmlFor="audio-upload"
                            className="cursor-pointer text-xs font-bold text-indigo-600 bg-white border border-indigo-100 px-4 py-2 rounded-xl shadow-sm hover:bg-indigo-50 hover:border-indigo-300 transition-all active:scale-95"
                          >
                            {formData.fileUrl ? 'Change File' : 'Browse Files'}
                          </label>
                        </>
                      )}
                    </div>

                    {(isUploadingFile || (uploadProgress > 0 && !editingId)) && (
                      <div className="space-y-2">
                        <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-wider">
                          <span className={showSuccess ? 'text-green-600' : 'text-indigo-600'}>
                            {showSuccess ? 'Status: Ready for publishing' : 'Status: Uploading to cloud...'}
                          </span>
                          <span className="text-slate-500">{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden shadow-inner">
                          <div 
                            className={`h-full transition-all duration-300 rounded-full ${showSuccess ? 'bg-green-500' : 'bg-indigo-600'}`}
                            style={{ width: `${uploadProgress}%` }}
                          />
                        </div>
                      </div>
                    )}

                    {errors.fileUrl && !isUploadingFile && (
                      <div className="flex items-center gap-1.5 p-2 bg-red-100/50 rounded-lg text-red-600">
                        <AlertCircle className="h-3.5 w-3.5" />
                        <span className="text-[10px] font-bold uppercase">{errors.fileUrl}</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-6">
                <button
                  type="button"
                  onClick={closeModal}
                  className="flex-grow py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-all active:scale-95"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={isUploadingFile || !formData.fileUrl}
                  className="flex-grow-[2] py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50 disabled:shadow-none active:scale-95"
                >
                  {editingId ? 'Save Changes' : 'Publish Content'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, Info, X, AlertCircle } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
}

const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB

const AdminDashboard: React.FC = () => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: 'https://picsum.photos/seed/new/800/600',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "Title is required";
    else if (formData.title.length < 3) newErrors.title = "Title must be at least 3 characters";

    if (!formData.preacher.trim()) newErrors.preacher = "Preacher/Speaker is required";

    if (!formData.datePreached) newErrors.datePreached = "Date is required";

    if (!formData.fileUrl) newErrors.fileUrl = "An audio file must be uploaded";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this media?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return alert("Please enter a description first.");
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Clear previous file errors
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      // Validation: Check if it's an MP3 file
      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Invalid format. Only MP3 files are allowed." }));
        return;
      }

      // Validation: Check file size (100MB)
      if (file.size > MAX_FILE_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File is too large. Maximum size is 100MB." }));
        return;
      }

      setIsUploadingFile(true);

      // Simulate an upload process
      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 25;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 200);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage your church's digital media assets.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Upload New Media</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Total Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
          <h2 className="font-bold text-slate-900">Recent Uploads</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50">
                <th className="px-6 py-4">Title</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 text-center">Stats</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <img src={media.thumbnailUrl} alt="" className="w-10 h-10 rounded-lg object-cover" />
                      <span className="font-bold text-slate-900">{media.title}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">{media.preacher}</td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2.5 py-1 rounded-full text-[10px] font-bold bg-indigo-50 text-indigo-600 uppercase">
                      {media.category}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col text-center text-xs font-medium text-slate-500">
                      <span>{media.playCount} plays</span>
                      <span>{media.downloadCount} dl</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">{new Date(media.datePreached).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                        title="Edit Details"
                      >
                        <Edit3 className="h-5 w-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                        title="Delete Media"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit Media Details' : 'Upload New Media'}</h3>
                <p className="text-xs text-slate-500 mt-0.5">Maintain your digital sanctuary by updating content.</p>
              </div>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto custom-scrollbar">
              <div className="space-y-4">
                <div className="bg-indigo-50 p-4 rounded-2xl border border-indigo-100 flex gap-4">
                  <div className="bg-indigo-600 p-2 rounded-lg h-fit shadow-md">
                    <Sparkles className="h-5 w-5 text-white" />
                  </div>
                  <div className="flex-grow">
                    <p className="text-sm font-bold text-indigo-900">FaithStream AI Assistant</p>
                    <p className="text-xs text-indigo-700 mb-3">Tell me about the message below and I'll help you refine the title.</p>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !formData.description}
                      className="text-xs font-bold bg-indigo-600 text-white px-3 py-1.5 rounded-lg disabled:opacity-50 flex items-center gap-2 transition-all hover:bg-indigo-700 active:scale-95"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      Refine Title
                    </button>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({...errors, title: undefined});
                      }}
                      placeholder="e.g. The Power of Grace"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.title ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Preacher / Speaker</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({...errors, preacher: undefined});
                      }}
                      placeholder="e.g. Pastor John Doe"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.preacher ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      {Object.values(Category).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Date Preached</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({...errors, datePreached: undefined});
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.datePreached ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.datePreached && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.datePreached}</p>}
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Description</label>
                  <textarea
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Briefly describe the theme of the message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Media File (MP3)</label>
                  <div className={`p-4 border rounded-2xl flex flex-col gap-4 transition-all ${
                    errors.fileUrl ? 'border-red-500 bg-red-50/30' : 
                    showSuccess ? 'border-green-300 bg-green-50/30' : 'bg-slate-50 border-slate-200'
                  }`}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-3">
                        <div className={`p-2.5 rounded-xl transition-all shadow-sm ${
                          showSuccess ? 'bg-green-600 text-white' : 
                          errors.fileUrl ? 'bg-red-600 text-white' : 
                          isUploadingFile ? 'bg-indigo-600 text-white animate-pulse' : 'bg-white border border-slate-200 text-indigo-600'
                        }`}>
                          {isUploadingFile ? <Loader2 className="h-5 w-5 animate-spin" /> : 
                           showSuccess ? <CheckCircle className="h-5 w-5" /> :
                           <Upload className="h-5 w-5" />}
                        </div>
                        <div>
                          <p className={`text-sm font-bold transition-colors ${
                            showSuccess ? 'text-green-700' : 
                            errors.fileUrl ? 'text-red-700' : 'text-slate-900'
                          }`}>
                            {isUploadingFile ? 'Uploading message...' : 
                             showSuccess ? 'Upload complete!' : 
                             'Select audio file'}
                          </p>
                          <p className="text-[11px] text-slate-500 font-medium">MP3 Format • Up to 100MB</p>
                        </div>
                      </div>

                      {!isUploadingFile && (
                        <>
                          <input
                            type="file"
                            accept="audio/mpeg"
                            onChange={handleFileChange}
                            className="hidden"
                            id="audio-upload"
                          />
                          <label
                            htmlFor="audio-upload"
                            className="cursor-pointer text-xs font-bold text-indigo-600 bg-white border border-indigo-100 px-4 py-2 rounded-xl shadow-sm hover:bg-indigo-50 hover:border-indigo-300 transition-all active:scale-95"
                          >
                            {formData.fileUrl ? 'Change File' : 'Browse Files'}
                          </label>
                        </>
                      )}
                    </div>

                    {(isUploadingFile || (uploadProgress > 0 && !editingId)) && (
                      <div className="space-y-2">
                        <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-wider">
                          <span className={showSuccess ? 'text-green-600' : 'text-indigo-600'}>
                            {showSuccess ? 'Status: Ready for publishing' : 'Status: Uploading to cloud...'}
                          </span>
                          <span className="text-slate-500">{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden shadow-inner">
                          <div 
                            className={`h-full transition-all duration-300 rounded-full ${showSuccess ? 'bg-green-500' : 'bg-indigo-600'}`}
                            style={{ width: `${uploadProgress}%` }}
                          />
                        </div>
                      </div>
                    )}

                    {errors.fileUrl && !isUploadingFile && (
                      <div className="flex items-center gap-1.5 p-2 bg-red-100/50 rounded-lg text-red-600">
                        <AlertCircle className="h-3.5 w-3.5" />
                        <span className="text-[10px] font-bold uppercase">{errors.fileUrl}</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-6">
                <button
                  type="button"
                  onClick={closeModal}
                  className="flex-grow py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-all active:scale-95"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={isUploadingFile || !formData.fileUrl}
                  className="flex-grow-[2] py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50 disabled:shadow-none active:scale-95"
                >
                  {editingId ? 'Save Changes' : 'Publish Content'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, Info, X, AlertCircle, FileAudio } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
}

const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB

const AdminDashboard: React.FC = () => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: 'https://picsum.photos/seed/new/800/600',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "Title is required";
    else if (formData.title.length < 3) newErrors.title = "Title must be at least 3 characters";

    if (!formData.preacher.trim()) newErrors.preacher = "Preacher/Speaker is required";

    if (!formData.datePreached) newErrors.datePreached = "Date is required";

    if (!formData.fileUrl) newErrors.fileUrl = "An audio file must be uploaded";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this media?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return alert("Please enter a description first.");
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Invalid format. Only MP3 files are allowed." }));
        return;
      }

      if (file.size > MAX_FILE_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File is too large. Maximum size is 100MB." }));
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 20;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 150);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage your church's digital media assets.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Upload New Media</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Total Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
          <h2 className="font-bold text-slate-900">Recent Uploads</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50">
                <th className="px-6 py-4">Title</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 text-center">Stats</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <img src={media.thumbnailUrl} alt="" className="w-10 h-10 rounded-lg object-cover" />
                      <span className="font-bold text-slate-900">{media.title}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">{media.preacher}</td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2.5 py-1 rounded-full text-[10px] font-bold bg-indigo-50 text-indigo-600 uppercase">
                      {media.category}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col text-center text-xs font-medium text-slate-500">
                      <span>{media.playCount} plays</span>
                      <span>{media.downloadCount} dl</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">{new Date(media.datePreached).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                        title="Edit Details"
                      >
                        <Edit3 className="h-5 w-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                        title="Delete Media"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit Media Details' : 'Upload New Media'}</h3>
                <p className="text-xs text-slate-500 mt-0.5">Maintain your digital sanctuary by updating content.</p>
              </div>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto custom-scrollbar">
              <div className="space-y-4">
                <div className="bg-indigo-50 p-4 rounded-2xl border border-indigo-100 flex gap-4">
                  <div className="bg-indigo-600 p-2 rounded-lg h-fit shadow-md">
                    <Sparkles className="h-5 w-5 text-white" />
                  </div>
                  <div className="flex-grow">
                    <p className="text-sm font-bold text-indigo-900">FaithStream AI Assistant</p>
                    <p className="text-xs text-indigo-700 mb-3">I'll suggest a polished title based on your description below.</p>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !formData.description}
                      className="text-xs font-bold bg-indigo-600 text-white px-3 py-1.5 rounded-lg disabled:opacity-50 flex items-center gap-2 transition-all hover:bg-indigo-700 active:scale-95"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      Refine Content
                    </button>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({...errors, title: undefined});
                      }}
                      placeholder="e.g. The Power of Grace"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.title ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Preacher / Speaker</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({...errors, preacher: undefined});
                      }}
                      placeholder="e.g. Pastor John Doe"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.preacher ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      {Object.values(Category).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Date Preached</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({...errors, datePreached: undefined});
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.datePreached ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.datePreached && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.datePreached}</p>}
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Description</label>
                  <textarea
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Briefly describe the message theme..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Media File (MP3)</label>
                  <div className={`p-5 border rounded-2xl flex flex-col gap-5 transition-all duration-300 ${
                    errors.fileUrl ? 'border-red-500 bg-red-50/30' : 
                    showSuccess ? 'border-green-300 bg-green-50/20' : 'bg-slate-50 border-slate-200'
                  }`}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-4">
                        <div className={`p-3 rounded-2xl transition-all shadow-sm ${
                          showSuccess ? 'bg-green-600 text-white' : 
                          errors.fileUrl ? 'bg-red-600 text-white' : 
                          isUploadingFile ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-indigo-600'
                        }`}>
                          {isUploadingFile ? <Loader2 className="h-6 w-6 animate-spin" /> : 
                           showSuccess ? <CheckCircle className="h-6 w-6" /> :
                           <FileAudio className="h-6 w-6" />}
                        </div>
                        <div>
                          <p className={`text-sm font-bold transition-colors ${
                            showSuccess ? 'text-green-700' : 
                            errors.fileUrl ? 'text-red-700' : 'text-slate-900'
                          }`}>
                            {isUploadingFile ? 'Uploading message to cloud...' : 
                             showSuccess ? 'Audio uploaded successfully' : 
                             'Attach sermon audio'}
                          </p>
                          <p className="text-[11px] text-slate-500 font-medium">MP3 format required • Max 100MB</p>
                        </div>
                      </div>

                      {!isUploadingFile && (
                        <>
                          <input
                            type="file"
                            accept="audio/mpeg"
                            onChange={handleFileChange}
                            className="hidden"
                            id="audio-upload"
                          />
                          <label
                            htmlFor="audio-upload"
                            className="cursor-pointer text-xs font-bold text-indigo-600 bg-white border border-indigo-200 px-4 py-2.5 rounded-xl shadow-sm hover:bg-indigo-50 hover:border-indigo-400 transition-all active:scale-95"
                          >
                            {formData.fileUrl ? 'Replace Audio' : 'Browse Cloud'}
                          </label>
                        </>
                      )}
                    </div>

                    {(isUploadingFile || (uploadProgress > 0)) && (
                      <div className="space-y-2.5">
                        <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-widest">
                          <span className={showSuccess ? 'text-green-600 flex items-center gap-1.5' : 'text-indigo-600'}>
                            {showSuccess && <CheckCircle className="h-3 w-3" />}
                            {showSuccess ? 'Upload finished' : 'Uploading...'}
                          </span>
                          <span className="text-slate-500">{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-2.5 bg-slate-200 rounded-full overflow-hidden shadow-inner relative">
                          <div 
                            className={`h-full transition-all duration-300 rounded-full shadow-lg ${showSuccess ? 'bg-green-500' : 'bg-indigo-600'}`}
                            style={{ width: `${uploadProgress}%` }}
                          />
                          {!showSuccess && (
                            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent w-full h-full animate-[shimmer_2s_infinite]" />
                          )}
                        </div>

                        {showSuccess && !isUploadingFile && (
                          <div className="flex items-center gap-2 text-[11px] font-bold text-green-700 bg-green-100/50 p-2.5 rounded-xl border border-green-200 animate-in fade-in slide-in-from-top-1">
                            <Info className="h-4 w-4" />
                            <span>This message is ready to be published to the congregation.</span>
                          </div>
                        )}
                      </div>
                    )}

                    {errors.fileUrl && !isUploadingFile && (
                      <div className="flex items-center gap-2 p-3 bg-red-100 text-red-700 rounded-xl border border-red-200">
                        <AlertCircle className="h-4 w-4" />
                        <span className="text-[11px] font-bold uppercase tracking-wider">{errors.fileUrl}</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-6">
                <button
                  type="button"
                  onClick={closeModal}
                  className="flex-grow py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-100 transition-all active:scale-95"
                >
                  Discard Changes
                </button>
                <button
                  type="submit"
                  disabled={isUploadingFile || !formData.fileUrl}
                  className="flex-grow-[2] py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50 disabled:shadow-none active:scale-95"
                >
                  {editingId ? 'Save & Update' : 'Publish to Library'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
      `}</style>
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, Info, X, AlertCircle, FileAudio, AlertTriangle } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
}

const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB limit

const AdminDashboard: React.FC = () => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: 'https://picsum.photos/seed/new/800/600',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    else if (formData.title.length < 3) newErrors.title = "Title must be at least 3 characters";

    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";

    if (!formData.datePreached) newErrors.datePreached = "The preaching date is required";

    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return;
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // 1. Reset upload state and clear previous file errors
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      // 2. Client-side Validation: Format check
      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Please select an MP3 file." }));
        // Reset file input value so user can retry same file name if they fix it
        e.target.value = '';
        return;
      }

      // 3. Client-side Validation: Size check
      if (file.size > MAX_FILE_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      // 4. Proceed with simulated upload
      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage and publish your digital church resources.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Add New Message</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Global Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50">
          <h2 className="font-bold text-slate-900">Message Library</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50">
                <th className="px-6 py-4">Title</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 text-center">Engagement</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <img src={media.thumbnailUrl} alt="" className="w-10 h-10 rounded-lg object-cover" />
                      <span className="font-bold text-slate-900 truncate max-w-[200px]">{media.title}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">{media.preacher}</td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2.5 py-1 rounded-full text-[10px] font-bold bg-indigo-50 text-indigo-600 uppercase">
                      {media.category}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col text-center text-xs font-medium text-slate-500">
                      <span>{media.playCount} plays</span>
                      <span>{media.downloadCount} dl</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">{new Date(media.datePreached).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                        title="Edit Details"
                      >
                        <Edit3 className="h-5 w-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                        title="Delete Media"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Refine Message Details' : 'Publish New Message'}</h3>
                <p className="text-xs text-slate-500 mt-0.5">Fill in the details below to share spiritual nourishment.</p>
              </div>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors">
