import React from 'react';
import { Search, Filter, Play, Download, Calendar, User, SlidersHorizontal, History, X, Trash2 } from 'lucide-react';
import { db } from '../services/db';
import { Media, Category } from '../types';

interface LibraryProps {
  onPlay: (media: Media) => void;
}

const SEARCH_HISTORY_KEY = 'faithstream_recent_searches';
const MAX_HISTORY = 5;

const Library: React.FC<LibraryProps> = ({ onPlay }) => {
  const [allMedia, setAllMedia] = React.useState<Media[]>([]);
  const [filteredMedia, setFilteredMedia] = React.useState<Media[]>([]);
  const [searchQuery, setSearchQuery] = React.useState('');
  const [selectedCategory, setSelectedCategory] = React.useState<string>('All');
  const [recentSearches, setRecentSearches] = React.useState<string[]>([]);

  // Load media and search history
  React.useEffect(() => {
    const data = db.getMedia();
    setAllMedia(data);
    setFilteredMedia(data);

    const savedHistory = localStorage.getItem(SEARCH_HISTORY_KEY);
    if (savedHistory) {
      setRecentSearches(JSON.parse(savedHistory));
    }
  }, []);

  // Filter logic
  React.useEffect(() => {
    let result = allMedia;

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(m => 
        m.title.toLowerCase().includes(q) || 
        m.preacher.toLowerCase().includes(q) ||
        m.description?.toLowerCase().includes(q)
      );
    }

    if (selectedCategory !== 'All') {
      result = result.filter(m => m.category === selectedCategory);
    }

    setFilteredMedia(result);

    // Save to history if query is long enough (simple debounce/stability check)
    const timeoutId = setTimeout(() => {
      if (searchQuery.trim().length >= 3) {
        updateHistory(searchQuery.trim());
      }
    }, 1000);

    return () => clearTimeout(timeoutId);
  }, [searchQuery, selectedCategory, allMedia]);

  const updateHistory = (query: string) => {
    setRecentSearches(prev => {
      const filtered = prev.filter(s => s.toLowerCase() !== query.toLowerCase());
      const updated = [query, ...filtered].slice(0, MAX_HISTORY);
      localStorage.setItem(SEARCH_HISTORY_KEY, JSON.stringify(updated));
      return updated;
    });
  };

  const clearHistory = () => {
    setRecentSearches([]);
    localStorage.removeItem(SEARCH_HISTORY_KEY);
  };

  const handleDownload = (e: React.MouseEvent, media: Media) => {
    e.stopPropagation();
    db.incrementDownload(media.id);
    const link = document.createElement('a');
    link.href = media.fileUrl;
    link.download = `${media.title}.mp3`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
          <h1 className="text-4xl font-bold text-slate-900">Media Library</h1>
          <p className="text-slate-500 text-lg">Browse through our complete collection of spiritual content.</p>
        </div>

        <div className="flex flex-col gap-4 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="relative flex-grow sm:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
              <input
                type="text"
                placeholder="Search title, preacher..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-10 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none text-slate-900"
              />
              {searchQuery && (
                <button 
                  onClick={() => setSearchQuery('')}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                >
                  <X className="h-4 w-4" />
                </button>
              )}
            </div>
            <div className="relative">
              <SlidersHorizontal className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none text-slate-900 font-medium"
              >
                <option value="All">All Categories</option>
                {Object.values(Category).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
              <Filter className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none" />
            </div>
          </div>

          {/* Recent Searches Pills */}
          {recentSearches.length > 0 && (
            <div className="flex flex-wrap items-center gap-2 animate-in fade-in slide-in-from-top-1 duration-300">
              <div className="flex items-center text-slate-400 mr-1">
                <History className="h-3.5 w-3.5 mr-1" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Recent:</span>
              </div>
              {recentSearches.map((term, idx) => (
                <button
                  key={idx}
                  onClick={() => setSearchQuery(term)}
                  className="px-3 py-1 bg-indigo-50 hover:bg-indigo-100 text-indigo-600 text-[11px] font-bold rounded-full border border-indigo-100 transition-all active:scale-95"
                >
                  {term}
                </button>
              ))}
              <button 
                onClick={clearHistory}
                className="p-1 text-slate-300 hover:text-red-500 transition-colors"
                title="Clear history"
              >
                <Trash2 className="h-3.5 w-3.5" />
              </button>
            </div>
          )}
        </div>
      </div>

      {filteredMedia.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredMedia.map((media) => (
            <div 
              key={media.id} 
              className="group bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-xl transition-all duration-300 overflow-hidden"
              onClick={() => onPlay(media)}
            >
              <div className="relative aspect-[4/3] overflow-hidden cursor-pointer">
                <img
                  src={media.thumbnailUrl}
                  alt={media.title}
                  className="w-full h-full object-cover transform transition-transform group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <div className="bg-white/90 backdrop-blur-sm p-4 rounded-full text-indigo-600 shadow-lg transform scale-90 group-hover:scale-100 transition-transform">
                    <Play className="h-6 w-6 fill-current" />
                  </div>
                </div>
                <div className="absolute top-2 right-2 bg-black/60 backdrop-blur-md text-white text-[10px] px-2 py-1 rounded-md font-bold">
                  {media.duration}
                </div>
                <div className="absolute bottom-3 left-3 bg-indigo-600 text-white text-[10px] uppercase tracking-wider px-2 py-1 rounded font-bold">
                  {media.category}
                </div>
              </div>

              <div className="p-5 space-y-4">
                <div className="space-y-1">
                  <h3 className="text-lg font-bold text-slate-900 group-hover:text-indigo-600 transition-colors line-clamp-1">
                    {media.title}
                  </h3>
                  <div className="flex flex-col space-y-1 text-xs text-slate-500">
                    <div className="flex items-center">
                      <User className="h-3 w-3 mr-1.5" />
                      {media.preacher}
                    </div>
                    <div className="flex items-center">
                      <Calendar className="h-3 w-3 mr-1.5" />
                      {new Date(media.datePreached).toLocaleDateString()}
                    </div>
                  </div>
                </div>

                <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                  <div className="flex items-center space-x-3 text-[10px] font-bold text-slate-400">
                    <span>{media.playCount.toLocaleString()} Plays</span>
                    <span>•</span>
                    <span>{media.downloadCount.toLocaleString()} DLs</span>
                  </div>
                  <button
                    onClick={(e) => handleDownload(e, media)}
                    className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    title="Download MP3"
                  >
                    <Download className="h-5 w-5" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="py-32 text-center bg-white rounded-3xl border border-dashed border-slate-300">
          <div className="max-w-xs mx-auto space-y-4">
            <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
              <Search className="h-10 w-10 text-slate-300" />
            </div>
            <h3 className="text-xl font-bold text-slate-900">No matches found</h3>
            <p className="text-slate-500">We couldn't find any media matching your current filters. Try adjusting your search.</p>
            <button
              onClick={() => { setSearchQuery(''); setSelectedCategory('All'); }}
              className="text-indigo-600 font-bold hover:underline"
            >
              Clear all filters
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Library;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, Info, X, AlertCircle, FileAudio, AlertTriangle, ImagePlus, FileImage } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC = () => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: 'https://picsum.photos/seed/default/800/600',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    else if (formData.title.length < 3) newErrors.title = "Title must be at least 3 characters";

    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";

    if (!formData.datePreached) newErrors.datePreached = "The preaching date is required";

    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";

    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return;
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      const objectUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Please select an MP3 file." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage and publish your digital church resources.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Add New Message</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Global Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50">
          <h2 className="font-bold text-slate-900">Message Library</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50 border-b border-slate-100">
                <th className="px-6 py-4">Title</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 text-center">Engagement</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="group hover:bg-indigo-50/30 transition-all even:bg-slate-50/40">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <img src={media.thumbnailUrl} alt="" className="w-10 h-10 rounded-lg object-cover ring-1 ring-slate-200 group-hover:ring-indigo-300 transition-all" />
                      <span className="font-bold text-slate-900 truncate max-w-[200px]">{media.title}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">{media.preacher}</td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2.5 py-1 rounded-full text-[10px] font-bold bg-indigo-50 text-indigo-600 uppercase">
                      {media.category}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col text-center text-xs font-medium text-slate-500">
                      <span className="group-hover:text-indigo-600 transition-colors">{media.playCount} plays</span>
                      <span>{media.downloadCount} dl</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">{new Date(media.datePreached).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-lg transition-all shadow-sm shadow-transparent hover:shadow-indigo-100"
                        title="Edit Details"
                      >
                        <Edit3 className="h-5 w-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-white rounded-lg transition-all shadow-sm shadow-transparent hover:shadow-red-100"
                        title="Delete Media"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Refine Message Details' : 'Publish New Message'}</h3>
                <p className="text-xs text-slate-500 mt-0.5">Fill in the details below to share spiritual nourishment.</p>
              </div>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto custom-scrollbar">
              <div className="space-y-6">
                {/* Thumbnail Upload Section */}
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Thumbnail Preview</label>
                  <div className="relative group">
                    <div className={`w-full h-48 rounded-2xl border-2 border-dashed transition-all flex flex-col items-center justify-center overflow-hidden bg-slate-50 ${
                      errors.thumbnailUrl ? 'border-red-400 bg-red-50/30' : 'border-slate-200 hover:border-indigo-400'
                    }`}>
                      {formData.thumbnailUrl ? (
                        <img src={formData.thumbnailUrl} alt="Preview" className="w-full h-full object-cover transition-opacity group-hover:opacity-75" />
                      ) : (
                        <div className="flex flex-col items-center text-slate-400 space-y-2">
                          <ImagePlus className="h-10 w-10" />
                          <p className="text-xs font-bold">Click to add thumbnail</p>
                        </div>
                      )}

                      <input 
                        type="file" 
                        accept="image/*" 
                        onChange={handleThumbnailChange} 
                        className="absolute inset-0 opacity-0 cursor-pointer"
                      />

                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none">
                         <div className="flex items-center space-x-2 text-white font-bold text-sm bg-white/20 backdrop-blur-md px-4 py-2 rounded-xl">
                           <FileImage className="h-5 w-5" />
                           <span>Update Image</span>
                         </div>
                      </div>
                    </div>
                    {errors.thumbnailUrl && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.thumbnailUrl}</p>}
                  </div>
                </div>

                {/* AI Assistant Banner */}
                <div className="bg-indigo-50 p-4 rounded-2xl border border-indigo-100 flex gap-4">
                  <div className="bg-indigo-600 p-2 rounded-lg h-fit shadow-md">
                    <Sparkles className="h-5 w-5 text-white" />
                  </div>
                  <div className="flex-grow">
                    <p className="text-sm font-bold text-indigo-900">FaithStream AI Assistant</p>
                    <p className="text-xs text-indigo-700 mb-3">I can polish your message title based on the description below.</p>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !formData.description}
                      className="text-xs font-bold bg-indigo-600 text-white px-3 py-1.5 rounded-lg disabled:opacity-50 flex items-center gap-2 transition-all hover:bg-indigo-700 active:scale-95"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      Refine Title
                    </button>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Message Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({...errors, title: undefined});
                      }}
                      placeholder="e.g. Overcoming Giants"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.title ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Preacher / Speaker</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({...errors, preacher: undefined});
                      }}
                      placeholder="e.g. Pastor John Doe"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.preacher ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      {Object.values(Category).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Date Delivered</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({...errors, datePreached: undefined});
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.datePreached ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.datePreached && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.datePreached}</p>}
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Description & Theme</label>
                  <textarea
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Briefly summarize the core message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Audio Asset (MP3 Required)</label>
                  <div className={`p-5 border rounded-2xl flex flex-col gap-5 transition-all duration-300 ${
                    errors.fileUrl ? 'border-red-500 bg-red-50/40' : 
                    showSuccess ? 'border-green-300 bg-green-50/20' : 'bg-slate-50 border-slate-200'
                  }`}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-4">
                        <div className={`p-3 rounded-2xl transition-all shadow-sm ${
                          showSuccess ? 'bg-green-600 text-white' : 
                          errors.fileUrl ? 'bg-red-600 text-white' : 
                          isUploadingFile ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-indigo-600'
                        }`}>
                          {isUploadingFile ? <Loader2 className="h-6 w-6 animate-spin" /> : 
                           showSuccess ? <CheckCircle className="h-6 w-6" /> :
                           errors.fileUrl ? <AlertTriangle className="h-6 w-6" /> :
                           <FileAudio className="h-6 w-6" />}
                        </div>
                        <div>
                          <p className={`text-sm font-bold transition-colors ${
                            showSuccess ? 'text-green-700' : 
                            errors.fileUrl ? 'text-red-700' : 'text-slate-900'
                          }`}>
                            {isUploadingFile ? 'Uploading to cloud...' : 
                             showSuccess ? 'Message audio ready' : 
                             errors.fileUrl ? 'Validation failed' :
                             'Attach sermon audio'}
                          </p>
                          <p className="text-[11px] text-slate-500 font-medium">
                            {errors.fileUrl ? 'Please correct the error' : 'MP3 Format • Max 100MB'}
                          </p>
                        </div>
                      </div>

                      {!isUploadingFile && (
                        <>
                          <input
                            type="file"
                            accept=".mp3,audio/mpeg"
                            onChange={handleFileChange}
                            className="hidden"
                            id="audio-upload"
                          />
                          <label
                            htmlFor="audio-upload"
                            className={`cursor-pointer text-xs font-bold px-4 py-2.5 rounded-xl shadow-sm border transition-all active:scale-95 ${
                              errors.fileUrl ? 'bg-red-50 text-red-600 border-red-200 hover:bg-red-100' : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50'
                            }`}
                          >
                            {formData.fileUrl ? 'Replace Audio' : 'Browse Local'}
                          </label>
                        </>
                      )}
                    </div>

                    {(isUploadingFile || (uploadProgress > 0)) && (
                      <div className="space-y-2.5">
                        <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-widest">
                          <span className={showSuccess ? 'text-green-600 flex items-center gap-1.5' : 'text-indigo-600'}>
                            {showSuccess && <CheckCircle className="h-3 w-3" />}
                            {showSuccess ? 'Upload Finished' : 'Processing Stream...'}
                          </span>
                          <span className="text-slate-500">{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-2.5 bg-slate-200 rounded-full overflow-hidden shadow-inner relative">
                          <div 
                            className={`h-full transition-all duration-300 rounded-full shadow-lg ${showSuccess ? 'bg-green-500' : 'bg-indigo-600'}`}
                            style={{ width: `${uploadProgress}%` }}
                          />
                          {!showSuccess && (
                            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent w-full h-full animate-[shimmer_2s_infinite]" />
                          )}
                        </div>

                        {showSuccess && !isUploadingFile && (
                          <div className="flex items-center gap-2 text-[11px] font-bold text-green-700 bg-green-100/60 p-2.5 rounded-xl border border-green-200/50 animate-in fade-in slide-in-from-top-1">
                            <Info className="h-4 w-4" />
                            <span>This asset is verified and ready for distribution.</span>
                          </div>
                        )}
                      </div>
                    )}

                    {errors.fileUrl && !isUploadingFile && (
                      <div className="flex items-center gap-2 p-3 bg-red-100 text-red-700 rounded-xl border border-red-200 animate-in shake-in-1">
                        <AlertCircle className="h-4 w-4" />
                        <span className="text-[11px] font-bold uppercase tracking-wider">{errors.fileUrl}</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-6">
                <button
                  type="button"
                  onClick={closeModal}
                  className="flex-grow py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-100 transition-all active:scale-95"
                >
                  Discard
                </button>
                <button
                  type="submit"
                  disabled={isUploadingFile || !!errors.fileUrl || !formData.fileUrl}
                  className="flex-grow-[2] py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50 disabled:shadow-none active:scale-95"
                >
                  {editingId ? 'Update Message' : 'Publish to Library'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .shake-in-1 {
          animation: shake 0.3s ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import AudioPlayer from './components/AudioPlayer';
import Home from './pages/Home';
import Library from './pages/Library';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import { AuthState, Media } from './types';

const App: React.FC = () => {
  const [auth, setAuth] = React.useState<AuthState>({
    isAdmin: localStorage.getItem('faithstream_auth') === 'true',
    user: null
  });
  const [currentMedia, setCurrentMedia] = React.useState<Media | null>(null);

  const handleLogin = (email: string) => {
    setAuth({ isAdmin: true, user: { id: '1', email } });
    localStorage.setItem('faithstream_auth', 'true');
  };

  const handleLogout = () => {
    setAuth({ isAdmin: false, user: null });
    localStorage.removeItem('faithstream_auth');
  };

  const handlePlayMedia = (media: Media) => {
    setCurrentMedia(media);
  };

  return (
    <Router>
      <div className="min-h-screen flex flex-col bg-slate-50 pb-32 md:pb-24">
        <Navbar isAdmin={auth.isAdmin} onLogout={handleLogout} />

        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home onPlay={handlePlayMedia} />} />
            <Route path="/library" element={<Library onPlay={handlePlayMedia} />} />
            <Route 
              path="/admin/login" 
              element={auth.isAdmin ? <Navigate to="/admin" /> : <AdminLogin onLogin={handleLogin} />} 
            />
            <Route 
              path="/admin" 
              element={auth.isAdmin ? <AdminDashboard onPlay={handlePlayMedia} /> : <Navigate to="/admin/login" />} 
            />
          </Routes>
        </main>

        <footer className="bg-white border-t border-slate-200 py-12 px-4 text-center text-slate-400 text-sm">
          <div className="max-w-7xl mx-auto space-y-4">
            <p className="font-bold text-slate-600 uppercase tracking-widest text-[10px]">FaithStream Platform • v1.0 MVP</p>
            <p>© {new Date().getFullYear()} Faith Community Church. All rights reserved.</p>
          </div>
        </footer>

        <AudioPlayer 
          media={currentMedia} 
          onClose={() => setCurrentMedia(null)} 
        />
      </div>
    </Router>
  );
};

export default App;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, Info, X, AlertCircle, FileAudio, AlertTriangle, ImagePlus, FileImage, Play } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    else if (formData.title.length < 3) newErrors.title = "Title must be at least 3 characters";

    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";

    if (!formData.datePreached) newErrors.datePreached = "The preaching date is required";

    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";

    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return;
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      const objectUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Please select an MP3 file." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage and publish your digital church resources.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Add New Message</span>
        </button>
      </div>

      {/* Analytics Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Global Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      {/* Media Management Table */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50">
          <h2 className="font-bold text-slate-900">Message Library</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50 border-b border-slate-100">
                <th className="px-6 py-4">Title</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 text-center">Engagement</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="group transition-all hover:bg-slate-50 odd:bg-white even:bg-slate-50/30">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <div className="relative flex-shrink-0 group/img">
                        <img 
                          src={media.thumbnailUrl} 
                          alt="" 
                          className="w-10 h-10 rounded-lg object-cover ring-1 ring-slate-200 transition-all group-hover:ring-indigo-300" 
                        />
                        {onPlay && (
                          <button 
                            onClick={() => onPlay(media)}
                            className="absolute inset-0 bg-black/40 opacity-0 group-hover/img:opacity-100 flex items-center justify-center rounded-lg transition-opacity"
                          >
                            <Play className="h-4 w-4 text-white fill-current" />
                          </button>
                        )}
                      </div>
                      <span className="font-bold text-slate-900 truncate max-w-[200px]">{media.title}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">{media.preacher}</td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2.5 py-1 rounded-full text-[10px] font-bold bg-indigo-50 text-indigo-600 uppercase">
                      {media.category}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col text-center text-xs font-medium text-slate-500">
                      <span className="group-hover:text-indigo-600 transition-colors">{media.playCount} plays</span>
                      <span>{media.downloadCount} dl</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">{new Date(media.datePreached).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-lg transition-all shadow-sm shadow-transparent hover:shadow-indigo-100"
                        title="Edit Details"
                      >
                        <Edit3 className="h-5 w-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-white rounded-lg transition-all shadow-sm shadow-transparent hover:shadow-red-100"
                        title="Delete Media"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Upload/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Refine Message Details' : 'Publish New Message'}</h3>
                <p className="text-xs text-slate-500 mt-0.5">Fill in the details below to share spiritual nourishment.</p>
              </div>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto custom-scrollbar">
              <div className="space-y-6">

                {/* Thumbnail Upload & Preview */}
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Cover Artwork / Thumbnail</label>
                  <div className={`relative group w-full h-48 rounded-2xl border-2 border-dashed transition-all flex flex-col items-center justify-center overflow-hidden bg-slate-50 ${
                    errors.thumbnailUrl ? 'border-red-400 bg-red-50/30' : 'border-slate-200 hover:border-indigo-400'
                  }`}>
                    {formData.thumbnailUrl ? (
                      <div className="w-full h-full relative">
                        <img src={formData.thumbnailUrl} alt="Preview" className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <div className="bg-white/90 backdrop-blur-sm px-4 py-2 rounded-xl text-indigo-600 text-xs font-bold flex items-center gap-2 shadow-xl">
                            <ImagePlus className="h-4 w-4" /> Change Thumbnail
                          </div>
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center text-slate-400 space-y-2">
                        <div className="p-3 bg-white rounded-xl shadow-sm border border-slate-100">
                          <ImagePlus className="h-6 w-6 text-indigo-500" />
                        </div>
                        <div className="text-center">
                          <p className="text-xs font-bold text-slate-600">Click to upload cover</p>
                          <p className="text-[10px] text-slate-400">JPG, PNG up to 5MB</p>
                        </div>
                      </div>
                    )}

                    <input 
                      type="file" 
                      accept="image/*" 
                      onChange={handleThumbnailChange} 
                      className="absolute inset-0 opacity-0 cursor-pointer"
                    />
                  </div>
                  {errors.thumbnailUrl && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.thumbnailUrl}</p>}
                </div>

                {/* AI Assistant Hook */}
                <div className="bg-indigo-50 p-4 rounded-2xl border border-indigo-100 flex gap-4">
                  <div className="bg-indigo-600 p-2 rounded-lg h-fit shadow-md">
                    <Sparkles className="h-5 w-5 text-white" />
                  </div>
                  <div className="flex-grow">
                    <p className="text-sm font-bold text-indigo-900">FaithStream AI Assistant</p>
                    <p className="text-xs text-indigo-700 mb-3">I can polish your message title based on the description below.</p>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !formData.description}
                      className="text-xs font-bold bg-indigo-600 text-white px-3 py-1.5 rounded-lg disabled:opacity-50 flex items-center gap-2 transition-all hover:bg-indigo-700 active:scale-95 shadow-md shadow-indigo-200"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      Refine Title
                    </button>
                  </div>
                </div>

                {/* Input Fields */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Message Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({...errors, title: undefined});
                      }}
                      placeholder="e.g. Overcoming Giants"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.title ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Preacher / Speaker</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({...errors, preacher: undefined});
                      }}
                      placeholder="e.g. Pastor John Doe"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.preacher ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      {Object.values(Category).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Date Delivered</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({...errors, datePreached: undefined});
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${
                        errors.datePreached ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.datePreached && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.datePreached}</p>}
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Description & Theme</label>
                  <textarea
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Briefly summarize the core message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>

                {/* Audio File Upload */}
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Audio Asset (MP3 Required)</label>
                  <div className={`p-5 border rounded-2xl flex flex-col gap-5 transition-all duration-300 ${
                    errors.fileUrl ? 'border-red-500 bg-red-50/40' : 
                    showSuccess ? 'border-green-300 bg-green-50/20' : 'bg-slate-50 border-slate-200'
                  }`}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-4">
                        <div className={`p-3 rounded-2xl transition-all shadow-sm ${
                          showSuccess ? 'bg-green-600 text-white' : 
                          errors.fileUrl ? 'bg-red-600 text-white' : 
                          isUploadingFile ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-indigo-600'
                        }`}>
                          {isUploadingFile ? <Loader2 className="h-6 w-6 animate-spin" /> : 
                           showSuccess ? <CheckCircle className="h-6 w-6" /> :
                           errors.fileUrl ? <AlertTriangle className="h-6 w-6" /> :
                           <FileAudio className="h-6 w-6" />}
                        </div>
                        <div>
                          <p className={`text-sm font-bold transition-colors ${
                            showSuccess ? 'text-green-700' : 
                            errors.fileUrl ? 'text-red-700' : 'text-slate-900'
                          }`}>
                            {isUploadingFile ? 'Uploading to cloud...' : 
                             showSuccess ? 'Message audio ready' : 
                             errors.fileUrl ? 'Validation failed' :
                             'Attach sermon audio'}
                          </p>
                          <p className="text-[11px] text-slate-500 font-medium">
                            {errors.fileUrl ? 'Please correct the error' : 'MP3 Format • Max 100MB'}
                          </p>
                        </div>
                      </div>

                      {!isUploadingFile && (
                        <>
                          <input
                            type="file"
                            accept=".mp3,audio/mpeg"
                            onChange={handleFileChange}
                            className="hidden"
                            id="audio-upload"
                          />
                          <label
                            htmlFor="audio-upload"
                            className={`cursor-pointer text-xs font-bold px-4 py-2.5 rounded-xl shadow-sm border transition-all active:scale-95 ${
                              errors.fileUrl ? 'bg-red-50 text-red-600 border-red-200 hover:bg-red-100' : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50'
                            }`}
                          >
                            {formData.fileUrl ? 'Replace Audio' : 'Browse Local'}
                          </label>
                        </>
                      )}
                    </div>

                    {(isUploadingFile || (uploadProgress > 0)) && (
                      <div className="space-y-2.5">
                        <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-widest">
                          <span className={showSuccess ? 'text-green-600 flex items-center gap-1.5' : 'text-indigo-600'}>
                            {showSuccess && <CheckCircle className="h-3 w-3" />}
                            {showSuccess ? 'Upload Finished' : 'Processing Stream...'}
                          </span>
                          <span className="text-slate-500">{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-2.5 bg-slate-200 rounded-full overflow-hidden shadow-inner relative">
                          <div 
                            className={`h-full transition-all duration-300 rounded-full shadow-lg ${showSuccess ? 'bg-green-500' : 'bg-indigo-600'}`}
                            style={{ width: `${uploadProgress}%` }}
                          />
                          {!showSuccess && (
                            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent w-full h-full animate-[shimmer_2s_infinite]" />
                          )}
                        </div>
                      </div>
                    )}

                    {errors.fileUrl && !isUploadingFile && (
                      <div className="flex items-center gap-2 p-3 bg-red-100 text-red-700 rounded-xl border border-red-200 animate-in shake-in-1">
                        <AlertCircle className="h-4 w-4" />
                        <span className="text-[11px] font-bold uppercase tracking-wider">{errors.fileUrl}</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex gap-4 pt-6 border-t border-slate-100 mt-4">
                <button
                  type="button"
                  onClick={closeModal}
                  className="flex-grow py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-100 transition-all active:scale-95"
                >
                  Discard
                </button>
                <button
                  type="submit"
                  disabled={isUploadingFile || !!errors.fileUrl || !formData.fileUrl}
                  className="flex-grow-[2] py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50 disabled:shadow-none active:scale-95"
                >
                  {editingId ? 'Update Message' : 'Publish to Library'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .shake-in-1 {
          animation: shake 0.3s ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, Info, X, AlertCircle, FileAudio, AlertTriangle, ImagePlus, FileImage, Play, Headphones } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";
    if (!formData.datePreached) newErrors.datePreached = "The preaching date is required";
    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";
    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return;
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      const objectUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Please select an MP3 file." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage and publish your digital church resources.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Add New Message</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Global Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      {/* Refined Media Management Table */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50">
          <h2 className="font-bold text-slate-900">Message Library</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50 border-b border-slate-100">
                <th className="px-6 py-4">Message</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4 text-center">Engagement</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="group transition-all hover:bg-indigo-50/30 even:bg-slate-50/50 relative">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <div className="relative h-12 w-12 flex-shrink-0 group/thumb">
                        <img 
                          src={media.thumbnailUrl || 'https://picsum.photos/seed/placeholder/200'} 
                          alt="" 
                          className="h-full w-full rounded-lg object-cover ring-1 ring-slate-200 group-hover:ring-indigo-300 transition-all shadow-sm" 
                        />
                        {onPlay && (
                          <button 
                            onClick={() => onPlay(media)}
                            className="absolute inset-0 bg-black/40 opacity-0 group-hover/thumb:opacity-100 flex items-center justify-center rounded-lg transition-opacity"
                          >
                            <Play className="h-4 w-4 text-white fill-current" />
                          </button>
                        )}
                      </div>
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-900 truncate max-w-[200px] leading-tight">{media.title}</span>
                        <span className="text-[10px] text-slate-400 font-medium">{media.duration} duration</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 font-medium">{media.preacher}</td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2.5 py-1 rounded-full text-[10px] font-bold bg-indigo-50 text-indigo-600 uppercase tracking-wide">
                      {media.category}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col items-center justify-center gap-1">
                      <div className="flex items-center space-x-4 text-[11px] font-bold text-slate-500">
                        <span className="flex items-center gap-1 group-hover:text-indigo-600 transition-colors"><Play className="h-3 w-3" /> {media.playCount}</span>
                        <span className="flex items-center gap-1 group-hover:text-green-600 transition-colors"><Upload className="h-3 w-3" /> {media.downloadCount}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500 font-medium">
                    {new Date(media.datePreached).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-1">
                      {onPlay && (
                        <button 
                          onClick={() => onPlay(media)}
                          className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-lg transition-all shadow-sm shadow-transparent hover:shadow-indigo-100"
                          title="Preview Audio"
                        >
                          <Headphones className="h-5 w-5" />
                        </button>
                      )}
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-amber-600 hover:bg-white rounded-lg transition-all shadow-sm shadow-transparent hover:shadow-amber-100"
                        title="Edit Details"
                      >
                        <Edit3 className="h-5 w-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-white rounded-lg transition-all shadow-sm shadow-transparent hover:shadow-red-100"
                        title="Delete Media"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  </td>
                  {/* Subtle focus indicator */}
                  <div className="absolute left-0 top-0 bottom-0 w-1 bg-indigo-600 opacity-0 group-hover:opacity-100 transition-opacity" />
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Upload/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Refine Message' : 'Publish New Content'}</h3>
                <p className="text-xs text-slate-500 mt-0.5">Manage details and assets for your community.</p>
              </div>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto custom-scrollbar">
              <div className="space-y-6">

                {/* Advanced Thumbnail Upload */}
                <div className="space-y-2">
                  <div className="flex justify-between items-center px-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Cover Artwork</label>
                    <span className="text-[10px] font-bold text-slate-400 uppercase">Recommended: 1600x1200</span>
                  </div>
                  <div className={`relative group w-full h-52 rounded-2xl border-2 border-dashed transition-all flex flex-col items-center justify-center overflow-hidden bg-slate-50 shadow-inner ${
                    errors.thumbnailUrl ? 'border-red-400 bg-red-50/30' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-100/50'
                  }`}>
                    {formData.thumbnailUrl ? (
                      <div className="w-full h-full relative">
                        <img src={formData.thumbnailUrl} alt="Preview" className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <div className="bg-white/90 backdrop-blur-sm px-4 py-2 rounded-xl text-indigo-600 text-xs font-bold flex items-center gap-2 shadow-xl transform translate-y-2 group-hover:translate-y-0 transition-transform">
                            <ImagePlus className="h-4 w-4" /> Replace Image
                          </div>
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center text-slate-400 space-y-3 p-6 text-center">
                        <div className="p-4 bg-white rounded-2xl shadow-sm border border-slate-100">
                          <ImagePlus className="h-8 w-8 text-indigo-500" />
                        </div>
                        <div>
                          <p className="text-sm font-bold text-slate-600">Upload Thumbnail</p>
                          <p className="text-xs text-slate-400">Click to browse your device for cover art</p>
                        </div>
                      </div>
                    )}

                    <input 
                      type="file" 
                      accept="image/*" 
                      onChange={handleThumbnailChange} 
                      className="absolute inset-0 opacity-0 cursor-pointer"
                    />
                  </div>
                  {errors.thumbnailUrl && <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1"><AlertCircle className="h-3 w-3" /> {errors.thumbnailUrl}</p>}
                </div>

                {/* AI Assistant Banner */}
                <div className="bg-indigo-50 p-4 rounded-2xl border border-indigo-100 flex gap-4 shadow-sm">
                  <div className="bg-indigo-600 p-2.5 rounded-xl h-fit shadow-md">
                    <Sparkles className="h-5 w-5 text-white" />
                  </div>
                  <div className="flex-grow">
                    <p className="text-sm font-bold text-indigo-900">FaithStream Intelligence</p>
                    <p className="text-xs text-indigo-700 mb-3 font-medium">I'll help optimize your title and tags based on the description.</p>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !formData.description}
                      className="text-xs font-bold bg-indigo-600 text-white px-4 py-2 rounded-lg disabled:opacity-50 flex items-center gap-2 transition-all hover:bg-indigo-700 active:scale-95 shadow-md shadow-indigo-200"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      Refine Metadata
                    </button>
                  </div>
                </div>

                {/* Primary Info */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Message Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({...errors, title: undefined});
                      }}
                      placeholder="e.g. Overcoming Giants"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium ${
                        errors.title ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Preacher / Speaker</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({...errors, preacher: undefined});
                      }}
                      placeholder="e.g. Pastor John Doe"
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium ${
                        errors.preacher ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-medium"
                    >
                      {Object.values(Category).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Date Delivered</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({...errors, datePreached: undefined});
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium ${
                        errors.datePreached ? 'border-red-500 ring-1 ring-red-500' : 'border-slate-200'
                      }`}
                    />
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Description & Summary</label>
                  <textarea
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Briefly describe the key message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none font-medium"
                  />
                </div>

                {/* Audio Asset Management */}
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide ml-1">Audio Source</label>
                  <div className={`p-5 border rounded-2xl flex flex-col gap-5 transition-all duration-300 ${
                    errors.fileUrl ? 'border-red-500 bg-red-50/40' : 
                    showSuccess ? 'border-green-300 bg-green-50/20' : 'bg-slate-50 border-slate-200 shadow-inner'
                  }`}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-4">
                        <div className={`p-3 rounded-2xl transition-all shadow-md ${
                          showSuccess ? 'bg-green-600 text-white' : 
                          errors.fileUrl ? 'bg-red-600 text-white' : 
                          isUploadingFile ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-100 text-indigo-600'
                        }`}>
                          {isUploadingFile ? <Loader2 className="h-6 w-6 animate-spin" /> : 
                           showSuccess ? <CheckCircle className="h-6 w-6" /> :
                           errors.fileUrl ? <AlertTriangle className="h-6 w-6" /> :
                           <FileAudio className="h-6 w-6" />}
                        </div>
                        <div>
                          <p className={`text-sm font-bold transition-colors ${
                            showSuccess ? 'text-green-700' : 
                            errors.fileUrl ? 'text-red-700' : 'text-slate-900'
                          }`}>
                            {isUploadingFile ? 'Processing...' : 
                             showSuccess ? 'Audio Asset Verified' : 
                             errors.fileUrl ? 'Upload Issue' :
                             'Attach Sermon MP3'}
                          </p>
                          <p className="text-[11px] text-slate-500 font-bold uppercase tracking-tighter">
                            {errors.fileUrl ? 'Check File Format' : 'MP3 Format • Max 100MB'}
                          </p>
                        </div>
                      </div>

                      {!isUploadingFile && (
                        <>
                          <input
                            type="file"
                            accept=".mp3,audio/mpeg"
                            onChange={handleFileChange}
                            className="hidden"
                            id="audio-upload"
                          />
                          <label
                            htmlFor="audio-upload"
                            className={`cursor-pointer text-xs font-bold px-5 py-2.5 rounded-xl shadow-sm border transition-all active:scale-95 ${
                              errors.fileUrl ? 'bg-red-50 text-red-600 border-red-200 hover:bg-red-100' : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50'
                            }`}
                          >
                            {formData.fileUrl ? 'Change File' : 'Choose File'}
                          </label>
                        </>
                      )}
                    </div>

                    {(isUploadingFile || (uploadProgress > 0)) && (
                      <div className="space-y-2.5 animate-in fade-in duration-500">
                        <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-widest text-slate-500">
                          <span>{showSuccess ? 'Complete' : 'Synchronizing...'}</span>
                          <span>{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden relative shadow-inner">
                          <div 
                            className={`h-full transition-all duration-300 rounded-full ${showSuccess ? 'bg-green-500' : 'bg-indigo-600'}`}
                            style={{ width: `${uploadProgress}%` }}
                          />
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex gap-4 pt-6 border-t border-slate-100 mt-4">
                <button
                  type="button"
                  onClick={closeModal}
                  className="flex-grow py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-all active:scale-95"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={isUploadingFile || !!errors.fileUrl || !formData.fileUrl}
                  className="flex-grow-[2] py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50 disabled:shadow-none active:scale-95 flex items-center justify-center gap-2"
                >
                  <CheckCircle className="h-5 w-5" />
                  {editingId ? 'Save Changes' : 'Publish Content'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .shake-in-1 {
          animation: shake 0.3s ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, X, ImagePlus, FileImage, Play, Headphones, CloudUpload, User, Calendar, Download } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);

  // Audio Upload States
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);

  // Thumbnail Upload States
  const [isUploadingThumb, setIsUploadingThumb] = React.useState(false);

  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setIsUploadingThumb(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";
    if (!formData.datePreached) newErrors.datePreached = "The preaching date is required";
    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";
    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleGenerateAI = async () => {
    if (!formData.description) return;
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      if (errors.title) setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      setIsUploadingThumb(true);

      // Artificial delay to simulate cloud processing for better UX feedback
      setTimeout(() => {
        const objectUrl = URL.createObjectURL(file);
        setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
        setIsUploadingThumb(false);
      }, 800);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Please select an MP3 file." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage and publish your digital church resources.</p>
        </div>
        <button
          onClick={handleAddNew}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
        >
          <Plus className="h-5 w-5" />
          <span>Add New Message</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
          { label: 'Global Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
          { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-4 rounded-2xl`}>
              <stat.icon className="h-8 w-8" />
            </div>
          </div>
        ))}
      </div>

      {/* Refined Media Management Table */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50">
          <h2 className="font-bold text-slate-900">Message Library</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs font-bold text-slate-500 uppercase tracking-wider border-b border-slate-100">
                <th className="px-6 py-4">Message</th>
                <th className="px-6 py-4">Preacher</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4">Stats</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {mediaList.map((media) => (
                <tr key={media.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <div className="relative w-12 h-12 flex-shrink-0">
                        <img src={media.thumbnailUrl} className="w-full h-full object-cover rounded-lg" alt="" />
                        <button 
                          onClick={() => onPlay?.(media)}
                          className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded-lg transition-opacity"
                        >
                          <Play className="h-4 w-4 text-white fill-current" />
                        </button>
                      </div>
                      <div>
                        <div className="text-sm font-bold text-slate-900 line-clamp-1">{media.title}</div>
                        <div className="text-[10px] font-bold text-indigo-600 uppercase tracking-wider">{media.category}</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center text-sm text-slate-600">
                      <User className="h-3.5 w-3.5 mr-2 text-slate-400" />
                      {media.preacher}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center text-sm text-slate-600">
                      <Calendar className="h-3.5 w-3.5 mr-2 text-slate-400" />
                      {new Date(media.datePreached).toLocaleDateString()}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col space-y-1">
                      <div className="flex items-center text-[10px] font-bold text-slate-500">
                        <Headphones className="h-3 w-3 mr-1" />
                        {media.playCount} PLAYS
                      </div>
                      <div className="flex items-center text-[10px] font-bold text-slate-500">
                        <Download className="h-3 w-3 mr-1" />
                        {media.downloadCount} DLs
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                      <button 
                        onClick={() => handleEdit(media)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                      >
                        <Edit3 className="h-4 w-4" />
                      </button>
                      <button 
                        onClick={() => handleDelete(media.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900 flex items-center">
                {editingId ? 'Edit Message' : 'Publish New Message'}
              </h3>
              <button onClick={closeModal} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 overflow-y-auto max-h-[70vh]">
              <div className="space-y-6">
                {/* Description & AI Generator */}
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase">Message Description</label>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={!formData.description || isGenerating}
                      className="flex items-center space-x-1 text-[11px] font-bold text-indigo-600 hover:text-indigo-700 disabled:opacity-50 transition-all"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      <span>{isGenerating ? 'GENERATE...' : 'GENERATE TITLE WITH AI'}</span>
                    </button>
                  </div>
                  <textarea
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    rows={3}
                    placeholder="Brief summary of the message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none text-sm"
                  />
                </div>

                {/* Basic Info */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Message Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                      className={`w-full px-4 py-3 bg-slate-50 border ${errors.title ? 'border-red-300' : 'border-slate-200'} rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Preacher</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => setFormData({ ...formData, preacher: e.target.value })}
                      className={`w-full px-4 py-3 bg-slate-50 border ${errors.preacher ? 'border-red-300' : 'border-slate-200'} rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
                    >
                      {Object.values(Category).map((cat) => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Date Preached</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => setFormData({ ...formData, datePreached: e.target.value })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
                    />
                  </div>
                </div>

                {/* Media Uploads */}
                <div className="space-y-4 pt-4 border-t border-slate-100">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    {/* Audio Upload */}
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Audio File (MP3)</label>
                      <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all ${showSuccess ? 'border-green-200 bg-green-50' : 'border-slate-200 hover:border-indigo-300 bg-slate-50'}`}>
                        {isUploadingFile ? (
                          <div className="space-y-3 py-2">
                            <div className="flex items-center justify-between text-[10px] font-bold text-slate-500">
                              <span>UPLOADING...</span>
                              <span>{uploadProgress}%</span>
                            </div>
                            <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                              <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }} />
                            </div>
                          </div>
                        ) : showSuccess ? (
                          <div className="flex items-center space-x-3 text-green-600 py-2">
                            <CheckCircle className="h-5 w-5" />
                            <span className="text-xs font-bold uppercase tracking-tight">Audio Ready</span>
                          </div>
                        ) : (
                          <label className="flex flex-col items-center justify-center cursor-pointer space-y-2 py-2">
                            <CloudUpload className="h-6 w-6 text-slate-400" />
                            <span className="text-[10px] font-bold text-slate-500 uppercase">Select MP3</span>
                            <input type="file" accept="audio/mpeg" className="hidden" onChange={handleFileChange} />
                          </label>
                        )}
                      </div>
                      {errors.fileUrl && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.fileUrl}</p>}
                    </div>

                    {/* Thumbnail Upload */}
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Thumbnail Image</label>
                      <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all ${formData.thumbnailUrl ? 'border-indigo-200 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300 bg-slate-50'}`}>
                        {isUploadingThumb ? (
                          <div className="flex flex-col items-center justify-center space-y-2 py-2">
                            <Loader2 className="h-6 w-6 text-indigo-600 animate-spin" />
                            <span className="text-[10px] font-bold text-slate-500">PROCESSING...</span>
                          </div>
                        ) : formData.thumbnailUrl ? (
                          <div className="relative group/thumb">
                            <img src={formData.thumbnailUrl} className="w-full h-12 object-cover rounded-lg" alt="" />
                            <label className="absolute inset-0 bg-black/40 opacity-0 group-hover/thumb:opacity-100 flex items-center justify-center rounded-lg cursor-pointer transition-opacity">
                              <ImagePlus className="h-4 w-4 text-white" />
                              <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
                            </label>
                          </div>
                        ) : (
                          <label className="flex flex-col items-center justify-center cursor-pointer space-y-2 py-2">
                            <FileImage className="h-6 w-6 text-slate-400" />
                            <span className="text-[10px] font-bold text-slate-500 uppercase">Upload Image</span>
                            <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
                          </label>
                        )}
                      </div>
                      {errors.thumbnailUrl && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.thumbnailUrl}</p>}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-10 flex items-center space-x-4">
                <button
                  type="submit"
                  className="flex-grow py-4 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
                >
                  {editingId ? 'Save Changes' : 'Publish Message'}
                </button>
                <button
                  type="button"
                  onClick={closeModal}
                  className="px-8 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-all"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

