      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900 flex items-center">
                {editingId ? 'Edit Message' : 'Publish New Message'}
              </h3>
              <button onClick={closeModal} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 overflow-y-auto max-h-[70vh]">
              <div className="space-y-6">
                {/* Description & AI Generator */}
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase">Message Description</label>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={!formData.description || isGenerating}
                      className="flex items-center space-x-1 text-[11px] font-bold text-indigo-600 hover:text-indigo-700 disabled:opacity-50 transition-all"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      <span>{isGenerating ? 'GENERATE...' : 'GENERATE TITLE WITH AI'}</span>
                    </button>
                  </div>
                  <textarea
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    rows={3}
                    placeholder="Brief summary of the message..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none text-sm"
                  />
                </div>

                {/* Basic Info */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Message Title</label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                      className={`w-full px-4 py-3 bg-slate-50 border ${errors.title ? 'border-red-300' : 'border-slate-200'} rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm`}
                    />
                    {errors.title && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.title}</p>}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Preacher</label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => setFormData({ ...formData, preacher: e.target.value })}
                      className={`w-full px-4 py-3 bg-slate-50 border ${errors.preacher ? 'border-red-300' : 'border-slate-200'} rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm`}
                    />
                    {errors.preacher && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.preacher}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
                    >
                      {Object.values(Category).map((cat) => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Date Preached</label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => setFormData({ ...formData, datePreached: e.target.value })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
                    />
                  </div>
                </div>

                {/* Media Uploads */}
                <div className="space-y-4 pt-4 border-t border-slate-100">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    {/* Audio Upload */}
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Audio File (MP3)</label>
                      <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all ${showSuccess ? 'border-green-200 bg-green-50' : 'border-slate-200 hover:border-indigo-300 bg-slate-50'}`}>
                        {isUploadingFile ? (
                          <div className="space-y-3 py-2">
                            <div className="flex items-center justify-between text-[10px] font-bold text-slate-500">
                              <span>UPLOADING...</span>
                              <span>{uploadProgress}%</span>
                            </div>
                            <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                              <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }} />
                            </div>
                          </div>
                        ) : showSuccess ? (
                          <div className="flex items-center space-x-3 text-green-600 py-2">
                            <CheckCircle className="h-5 w-5" />
                            <span className="text-xs font-bold uppercase tracking-tight">Audio Ready</span>
                          </div>
                        ) : (
                          <label className="flex flex-col items-center justify-center cursor-pointer space-y-2 py-2">
                            <CloudUpload className="h-6 w-6 text-slate-400" />
                            <span className="text-[10px] font-bold text-slate-500 uppercase">Select MP3</span>
                            <input type="file" accept="audio/mpeg" className="hidden" onChange={handleFileChange} />
                          </label>
                        )}
                      </div>
                      {errors.fileUrl && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.fileUrl}</p>}
                    </div>

                    {/* Thumbnail Upload */}
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Thumbnail Image</label>
                      <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all ${formData.thumbnailUrl ? 'border-indigo-200 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300 bg-slate-50'}`}>
                        {isUploadingThumb ? (
                          <div className="flex flex-col items-center justify-center space-y-2 py-2">
                            <Loader2 className="h-6 w-6 text-indigo-600 animate-spin" />
                            <span className="text-[10px] font-bold text-slate-500">PROCESSING...</span>
                          </div>
                        ) : formData.thumbnailUrl ? (
                          <div className="relative group/thumb">
                            <img src={formData.thumbnailUrl} className="w-full h-12 object-cover rounded-lg" alt="" />
                            <label className="absolute inset-0 bg-black/40 opacity-0 group-hover/thumb:opacity-100 flex items-center justify-center rounded-lg cursor-pointer transition-opacity">
                              <ImagePlus className="h-4 w-4 text-white" />
                              <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
                            </label>
                          </div>
                        ) : (
                          <label className="flex flex-col items-center justify-center cursor-pointer space-y-2 py-2">
                            <FileImage className="h-6 w-6 text-slate-400" />
                            <span className="text-[10px] font-bold text-slate-500 uppercase">Upload Image</span>
                            <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
                          </label>
                        )}
                      </div>
                      {errors.thumbnailUrl && <p className="text-[10px] text-red-500 font-bold mt-1">{errors.thumbnailUrl}</p>}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-10 flex items-center space-x-4">
                <button
                  type="submit"
                  className="flex-grow py-4 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
                >
                  {editingId ? 'Save Changes' : 'Publish Message'}
                </button>
                <button
                  type="button"
                  onClick={closeModal}
                  className="px-8 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-all"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Music, Lock, Mail, ArrowRight, AlertCircle } from 'lucide-react';
import { db } from '../services/db';

interface AdminLoginProps {
  onLogin: (email: string) => void;
}

const AdminLogin: React.FC<AdminLoginProps> = ({ onLogin }) => {
  const [email, setEmail] = React.useState('');
  const [password, setPassword] = React.useState('');
  const [error, setError] = React.useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const admins = db.getAdmins();
    const isAdmin = admins.find(a => a.email.toLowerCase() === email.toLowerCase());

    // In this demo, password check is simplified to any password longer than 5 chars
    // for authorized admin emails.
    if (isAdmin && password.length >= 6) {
      onLogin(email);
    } else if (!isAdmin) {
      setError('Access Denied. This email is not registered as an administrator.');
    } else {
      setError('Invalid password. Passwords must be at least 6 characters.');
    }
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center px-4">
      <div className="w-full max-w-md bg-white p-10 rounded-3xl border border-slate-200 shadow-2xl space-y-8">
        <div className="text-center space-y-2">
          <div className="bg-indigo-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-200">
            <Music className="h-8 w-8 text-white" />
          </div>
          <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Admin Portal</h1>
          <p className="text-slate-500">Secure access for the media team.</p>
        </div>

        {error && (
          <div className="bg-red-50 border border-red-100 p-4 rounded-xl flex items-start gap-3 animate-in fade-in slide-in-from-top-2">
            <AlertCircle className="h-5 w-5 text-red-500 shrink-0 mt-0.5" />
            <p className="text-xs font-bold text-red-700 leading-normal">{error}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase ml-1">Email Address</label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="admin@church.com"
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                />
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase ml-1">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="Minimum 6 characters"
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                />
              </div>
              <p className="text-[10px] text-slate-400 ml-1">Demo Hint: Try "password123" with admin@church.com</p>
            </div>
          </div>

          <button
            type="submit"
            className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 flex items-center justify-center space-x-2 group"
          >
            <span>Sign In</span>
            <ArrowRight className="h-5 w-5 transition-transform group-hover:translate-x-1" />
          </button>

          <p className="text-center text-xs text-slate-400">
            Access restricted to authorized personnel.
          </p>
        </form>
      </div>
    </div>
  );
};

export default AdminLogin;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, X, ImagePlus, FileImage, Play, Headphones, CloudUpload, User, Calendar, Download, Users, ShieldCheck, Mail, AlertCircle } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category, Admin } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [activeTab, setActiveTab] = React.useState<'library' | 'users'>('library');
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [adminList, setAdminList] = React.useState<Admin[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isAdminModalOpen, setIsAdminModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);

  // Audio Upload States
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);

  // Thumbnail Upload States
  const [isUploadingThumb, setIsUploadingThumb] = React.useState(false);

  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const [newAdminEmail, setNewAdminEmail] = React.useState('');

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
    setAdminList(db.getAdmins());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setIsUploadingThumb(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";
    if (!formData.datePreached) newErrors.datePreached = "A valid preaching date is required";
    if (!formData.description.trim()) newErrors.description = "A brief description helps members find content";
    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";
    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (newAdminEmail) {
      db.addAdmin(newAdminEmail);
      setAdminList(db.getAdmins());
      setNewAdminEmail('');
      setIsAdminModalOpen(false);
    }
  };

  const handleRemoveAdmin = (id: string) => {
    if (confirm('Are you sure you want to revoke this user\'s admin privileges?')) {
      db.removeAdmin(id);
      setAdminList(db.getAdmins());
    }
  };

  const handleGenerateAI = async () => {
    if (!formData.description) {
      setErrors(prev => ({ ...prev, description: "Enter a description first so AI can analyze it" }));
      return;
    }
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file (PNG/JPG)." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      setIsUploadingThumb(true);

      setTimeout(() => {
        const objectUrl = URL.createObjectURL(file);
        setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
        setIsUploadingThumb(false);
      }, 800);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Only MP3 files are accepted." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage content and church media team.</p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => setIsAdminModalOpen(true)}
            className="flex items-center space-x-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-50 transition-all shadow-sm"
          >
            <Users className="h-4 w-4" />
            <span>Add Admin</span>
          </button>
          <button
            onClick={handleAddNew}
            className="flex items-center space-x-2 px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
          >
            <Plus className="h-5 w-5" />
            <span>New Message</span>
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex space-x-1 bg-slate-200/50 p-1 rounded-2xl w-fit">
        <button
          onClick={() => setActiveTab('library')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'library' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          Message Library
        </button>
        <button
          onClick={() => setActiveTab('users')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          Team Management
        </button>
      </div>

      {activeTab === 'library' ? (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[
              { label: 'Total Messages', value: mediaList.length, icon: Upload, color: 'bg-blue-50 text-blue-600' },
              { label: 'Global Plays', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-indigo-50 text-indigo-600' },
              { label: 'Total Downloads', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-green-50 text-green-600' },
            ].map((stat) => (
              <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
                <div>
                  <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
                  <p className="text-3xl font-bold text-slate-900 mt-1">{stat.value}</p>
                </div>
                <div className={`${stat.color} p-4 rounded-2xl`}>
                  <stat.icon className="h-8 w-8" />
                </div>
              </div>
            ))}
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50">
              <h2 className="font-bold text-slate-900">Message Library</h2>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-xs font-bold text-slate-500 uppercase tracking-wider border-b border-slate-100">
                    <th className="px-6 py-4">Message</th>
                    <th className="px-6 py-4">Preacher</th>
                    <th className="px-6 py-4">Date</th>
                    <th className="px-6 py-4">Stats</th>
                    <th className="px-6 py-4 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {mediaList.map((media) => (
                    <tr key={media.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="relative w-12 h-12 flex-shrink-0">
                            <img src={media.thumbnailUrl} className="w-full h-full object-cover rounded-lg" alt="" />
                            <button 
                              onClick={() => onPlay?.(media)}
                              className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded-lg transition-opacity"
                            >
                              <Play className="h-4 w-4 text-white fill-current" />
                            </button>
                          </div>
                          <div>
                            <div className="text-sm font-bold text-slate-900 line-clamp-1">{media.title}</div>
                            <div className="text-[10px] font-bold text-indigo-600 uppercase tracking-wider">{media.category}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-sm text-slate-600">
                          <User className="h-3.5 w-3.5 mr-2 text-slate-400" />
                          {media.preacher}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-sm text-slate-600">
                          <Calendar className="h-3.5 w-3.5 mr-2 text-slate-400" />
                          {new Date(media.datePreached).toLocaleDateString()}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col space-y-1">
                          <div className="flex items-center text-[10px] font-bold text-slate-500">
                            <Headphones className="h-3 w-3 mr-1" />
                            {media.playCount} PLAYS
                          </div>
                          <div className="flex items-center text-[10px] font-bold text-slate-500">
                            <Download className="h-3 w-3 mr-1" />
                            {media.downloadCount} DLs
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end space-x-2">
                          <button 
                            onClick={() => handleEdit(media)}
                            className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                          >
                            <Edit3 className="h-4 w-4" />
                          </button>
                          <button 
                            onClick={() => handleDelete(media.id)}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                          >
                            <Trash2 className="h-4 w-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </>
      ) : (
        <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm max-w-4xl">
          <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
            <h2 className="font-bold text-slate-900">Registered Administrators</h2>
            <span className="text-xs font-medium text-slate-500 bg-slate-200 px-2 py-1 rounded-md">{adminList.length} Total</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-xs font-bold text-slate-500 uppercase tracking-wider border-b border-slate-100">
                  <th className="px-6 py-4">Email Address</th>
                  <th className="px-6 py-4">Role</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {adminList.map((admin) => (
                  <tr key={admin.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center text-sm font-medium text-slate-900">
                        <Mail className="h-4 w-4 mr-3 text-slate-400" />
                        {admin.email}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                        <ShieldCheck className="h-3 w-3 mr-1" /> Full Access
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      {adminList.length > 1 && (
                        <button 
                          onClick={() => handleRemoveAdmin(admin.id)}
                          className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Admin Add Modal */}
      {isAdminModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsAdminModalOpen(false)} />
          <div className="relative bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
              <h3 className="text-xl font-bold text-slate-900">Add Team Member</h3>
              <button onClick={() => setIsAdminModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                <X className="h-6 w-6" />
              </button>
            </div>
            <form onSubmit={handleAddAdmin} className="p-8 space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase ml-1">Admin Email</label>
                <input
                  type="email"
                  required
                  value={newAdminEmail}
                  onChange={(e) => setNewAdminEmail(e.target.value)}
                  placeholder="name@church.com"
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                />
              </div>
              <button
                type="submit"
                className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
              >
                Register Admin
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Media Modal with Comprehensive Validation */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={closeModal} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900 flex items-center">
                {editingId ? 'Edit Message' : 'Publish New Message'}
              </h3>
              <button onClick={closeModal} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 overflow-y-auto max-h-[70vh] custom-scrollbar">
              <div className="space-y-6">
                {/* Description & AI Generator */}
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase">Message Description <span className="text-red-500">*</span></label>
                    <button
                      type="button"
                      onClick={handleGenerateAI}
                      disabled={isGenerating}
                      className="flex items-center space-x-1 text-[11px] font-bold text-indigo-600 hover:text-indigo-700 disabled:opacity-50 transition-all"
                    >
                      {isGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                      <span>{isGenerating ? 'GENERATE...' : 'GENERATE TITLE WITH AI'}</span>
                    </button>
                  </div>
                  <textarea
                    value={formData.description}
                    onChange={(e) => {
                      setFormData({ ...formData, description: e.target.value });
                      if (errors.description) setErrors({ ...errors, description: undefined });
                    }}
                    rows={3}
                    placeholder="Brief summary of the message..."
                    className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none text-sm ${
                      errors.description ? 'border-red-400 bg-red-50/30 ring-1 ring-red-400' : 'border-slate-200'
                    }`}
                  />
                  {errors.description && (
                    <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 animate-in slide-in-from-left-2">
                      <AlertCircle className="h-3 w-3" /> {errors.description}
                    </p>
                  )}
                </div>

                {/* Basic Info */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Message Title <span className="text-red-500">*</span></label>
                    <input
                      type="text"
                      value={formData.title}
                      onChange={(e) => {
                        setFormData({ ...formData, title: e.target.value });
                        if (errors.title) setErrors({ ...errors, title: undefined });
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm ${
                        errors.title ? 'border-red-400 bg-red-50/30 ring-1 ring-red-400' : 'border-slate-200'
                      }`}
                    />
                    {errors.title && (
                      <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 animate-in slide-in-from-left-2">
                        <AlertCircle className="h-3 w-3" /> {errors.title}
                      </p>
                    )}
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Preacher <span className="text-red-500">*</span></label>
                    <input
                      type="text"
                      value={formData.preacher}
                      onChange={(e) => {
                        setFormData({ ...formData, preacher: e.target.value });
                        if (errors.preacher) setErrors({ ...errors, preacher: undefined });
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm ${
                        errors.preacher ? 'border-red-400 bg-red-50/30 ring-1 ring-red-400' : 'border-slate-200'
                      }`}
                    />
                    {errors.preacher && (
                      <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 animate-in slide-in-from-left-2">
                        <AlertCircle className="h-3 w-3" /> {errors.preacher}
                      </p>
                    )}
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Category</label>
                    <select
                      value={formData.category}
                      onChange={(e) => setFormData({ ...formData, category: e.target.value as Category })}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
                    >
                      {Object.values(Category).map((cat) => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase">Date Preached <span className="text-red-500">*</span></label>
                    <input
                      type="date"
                      value={formData.datePreached}
                      onChange={(e) => {
                        setFormData({ ...formData, datePreached: e.target.value });
                        if (errors.datePreached) setErrors({ ...errors, datePreached: undefined });
                      }}
                      className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm ${
                        errors.datePreached ? 'border-red-400 bg-red-50/30 ring-1 ring-red-400' : 'border-slate-200'
                      }`}
                    />
                    {errors.datePreached && (
                      <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 animate-in slide-in-from-left-2">
                        <AlertCircle className="h-3 w-3" /> {errors.datePreached}
                      </p>
                    )}
                  </div>
                </div>

                {/* Media Uploads */}
                <div className="space-y-4 pt-4 border-t border-slate-100">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    {/* Audio Upload */}
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Audio File (MP3) <span className="text-red-500">*</span></label>
                      <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all ${
                        errors.fileUrl ? 'border-red-400 bg-red-50/30' : 
                        showSuccess ? 'border-green-200 bg-green-50' : 'border-slate-200 hover:border-indigo-300 bg-slate-50'
                      }`}>
                        {isUploadingFile ? (
                          <div className="space-y-3 py-2">
                            <div className="flex items-center justify-between text-[10px] font-bold text-slate-500">
                              <span>UPLOADING...</span>
                              <span>{uploadProgress}%</span>
                            </div>
                            <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                              <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }} />
                            </div>
                          </div>
                        ) : showSuccess ? (
                          <div className="flex items-center justify-between py-2">
                            <div className="flex items-center space-x-3 text-green-600">
                              <CheckCircle className="h-5 w-5" />
                              <span className="text-xs font-bold uppercase tracking-tight">Audio Ready</span>
                            </div>
                            <button 
                              type="button"
                              onClick={() => { setShowSuccess(false); setFormData(p => ({ ...p, fileUrl: '' })); }}
                              className="text-[10px] font-bold text-slate-400 hover:text-red-500"
                            >
                              REMOVE
                            </button>
                          </div>
                        ) : (
                          <label className="flex flex-col items-center justify-center cursor-pointer space-y-2 py-2">
                            <CloudUpload className="h-6 w-6 text-slate-400" />
                            <span className="text-[10px] font-bold text-slate-500 uppercase">Select MP3</span>
                            <input type="file" accept="audio/mpeg" className="hidden" onChange={handleFileChange} />
                          </label>
                        )}
                      </div>
                      {errors.fileUrl && (
                        <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 animate-in slide-in-from-left-2">
                          <AlertCircle className="h-3 w-3" /> {errors.fileUrl}
                        </p>
                      )}
                    </div>

                    {/* Thumbnail Upload */}
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Thumbnail Image <span className="text-red-500">*</span></label>
                      <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all ${
                        errors.thumbnailUrl ? 'border-red-400 bg-red-50/30' :
                        formData.thumbnailUrl ? 'border-indigo-200 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300 bg-slate-50'
                      }`}>
                        {isUploadingThumb ? (
                          <div className="flex flex-col items-center justify-center space-y-2 py-2">
                            <Loader2 className="h-6 w-6 text-indigo-600 animate-spin" />
                            <span className="text-[10px] font-bold text-slate-500">PROCESSING...</span>
                          </div>
                        ) : formData.thumbnailUrl ? (
                          <div className="relative group/thumb">
                            <img src={formData.thumbnailUrl} className="w-full h-12 object-cover rounded-lg" alt="" />
                            <label className="absolute inset-0 bg-black/40 opacity-0 group-hover/thumb:opacity-100 flex items-center justify-center rounded-lg cursor-pointer transition-opacity">
                              <ImagePlus className="h-4 w-4 text-white" />
                              <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
                            </label>
                          </div>
                        ) : (
                          <label className="flex flex-col items-center justify-center cursor-pointer space-y-2 py-2">
                            <FileImage className="h-6 w-6 text-slate-400" />
                            <span className="text-[10px] font-bold text-slate-500 uppercase">Upload Image</span>
                            <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
                          </label>
                        )}
                      </div>
                      {errors.thumbnailUrl && (
                        <p className="text-[10px] text-red-500 font-bold flex items-center gap-1 animate-in slide-in-from-left-2">
                          <AlertCircle className="h-3 w-3" /> {errors.thumbnailUrl}
                        </p>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-10 flex items-center space-x-4">
                <button
                  type="submit"
                  disabled={isUploadingFile || isUploadingThumb}
                  className="flex-grow py-4 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 disabled:opacity-50 disabled:shadow-none"
                >
                  {editingId ? 'Save Changes' : 'Publish Message'}
                </button>
                <button
                  type="button"
                  onClick={closeModal}
                  className="px-8 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-all"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, X, ImagePlus, FileImage, Play, Headphones, CloudUpload, User, Calendar, Download, Users, ShieldCheck, Mail, AlertCircle } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category, Admin } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [activeTab, setActiveTab] = React.useState<'library' | 'users'>('library');
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [adminList, setAdminList] = React.useState<Admin[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isAdminModalOpen, setIsAdminModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);

  // Audio Upload States
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);

  // Thumbnail Upload States
  const [isUploadingThumb, setIsUploadingThumb] = React.useState(false);

  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const [newAdminEmail, setNewAdminEmail] = React.useState('');

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
    setAdminList(db.getAdmins());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setIsUploadingThumb(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";
    if (!formData.datePreached) newErrors.datePreached = "A valid preaching date is required";
    if (!formData.description.trim()) newErrors.description = "A brief description helps members find content";
    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";
    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (newAdminEmail) {
      db.addAdmin(newAdminEmail);
      setAdminList(db.getAdmins());
      setNewAdminEmail('');
      setIsAdminModalOpen(false);
    }
  };

  const handleRemoveAdmin = (id: string) => {
    if (confirm('Are you sure you want to revoke this user\'s admin privileges?')) {
      db.removeAdmin(id);
      setAdminList(db.getAdmins());
    }
  };

  const handleGenerateAI = async () => {
    if (!formData.description) {
      setErrors(prev => ({ ...prev, description: "Enter a description first so AI can analyze it" }));
      return;
    }
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file (PNG/JPG)." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      setIsUploadingThumb(true);

      setTimeout(() => {
        const objectUrl = URL.createObjectURL(file);
        setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
        setIsUploadingThumb(false);
      }, 800);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Only MP3 files are accepted." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
