import React from 'react';
import { Search, Filter, Play, Download, Calendar, User, SlidersHorizontal, History, X, Trash2 } from 'lucide-react';
import { db } from '../services/db';
import { Media, Category } from '../types';

interface LibraryProps {
  onPlay: (media: Media) => void;
}

const SEARCH_HISTORY_KEY = 'faithstream_recent_searches';
const MAX_HISTORY = 5;

const Library: React.FC<LibraryProps> = ({ onPlay }) => {
  const [allMedia, setAllMedia] = React.useState<Media[]>([]);
  const [filteredMedia, setFilteredMedia] = React.useState<Media[]>([]);
  const [searchQuery, setSearchQuery] = React.useState('');
  const [selectedCategory, setSelectedCategory] = React.useState<string>('All');
  const [recentSearches, setRecentSearches] = React.useState<string[]>([]);

  React.useEffect(() => {
    const data = db.getMedia();
    setAllMedia(data);
    setFilteredMedia(data);

    const savedHistory = localStorage.getItem(SEARCH_HISTORY_KEY);
    if (savedHistory) {
      setRecentSearches(JSON.parse(savedHistory));
    }
  }, []);

  React.useEffect(() => {
    let result = allMedia;

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(m => 
        m.title.toLowerCase().includes(q) || 
        m.preacher.toLowerCase().includes(q) ||
        m.description?.toLowerCase().includes(q)
      );
    }

    if (selectedCategory !== 'All') {
      result = result.filter(m => m.category === selectedCategory);
    }

    setFilteredMedia(result);

    const timeoutId = setTimeout(() => {
      if (searchQuery.trim().length >= 3) {
        updateHistory(searchQuery.trim());
      }
    }, 1000);

    return () => clearTimeout(timeoutId);
  }, [searchQuery, selectedCategory, allMedia]);

  const updateHistory = (query: string) => {
    setRecentSearches(prev => {
      const filtered = prev.filter(s => s.toLowerCase() !== query.toLowerCase());
      const updated = [query, ...filtered].slice(0, MAX_HISTORY);
      localStorage.setItem(SEARCH_HISTORY_KEY, JSON.stringify(updated));
      return updated;
    });
  };

  const clearHistory = () => {
    setRecentSearches([]);
    localStorage.removeItem(SEARCH_HISTORY_KEY);
  };

  const handleDownload = (e: React.MouseEvent, media: Media) => {
    e.stopPropagation();
    db.incrementDownload(media.id);
    const link = document.createElement('a');
    link.href = media.fileUrl;
    link.download = `${media.title}.mp3`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
          <h1 className="text-4xl font-bold text-slate-900 font-serif">Message Library</h1>
          <p className="text-slate-500 text-lg">Browse our spiritual archives for your edification.</p>
        </div>

        <div className="flex flex-col gap-4 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="relative flex-grow sm:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
              <input
                type="text"
                placeholder="Search title, preacher..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-10 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-red-600 outline-none text-slate-900 shadow-sm"
              />
              {searchQuery && (
                <button 
                  onClick={() => setSearchQuery('')}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-red-700 p-1"
                >
                  <X className="h-4 w-4" />
                </button>
              )}
            </div>
            <div className="relative">
              <SlidersHorizontal className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-red-600 outline-none text-slate-900 font-bold"
              >
                <option value="All">All Categories</option>
                {Object.values(Category).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
              <Filter className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none" />
            </div>
          </div>

          {recentSearches.length > 0 && (
            <div className="flex flex-wrap items-center gap-2 animate-in fade-in slide-in-from-top-1">
              <div className="flex items-center text-slate-400 mr-1">
                <History className="h-3.5 w-3.5 mr-1" />
                <span className="text-[10px] font-bold uppercase tracking-widest">History:</span>
              </div>
              {recentSearches.map((term, idx) => (
                <button
                  key={idx}
                  onClick={() => setSearchQuery(term)}
                  className="px-3 py-1 bg-red-50 hover:bg-red-100 text-red-700 text-[11px] font-bold rounded-full border border-red-100 transition-all shadow-sm"
                >
                  {term}
                </button>
              ))}
              <button onClick={clearHistory} className="p-1 text-slate-300 hover:text-red-600 transition-colors">
                <Trash2 className="h-3.5 w-3.5" />
              </button>
            </div>
          )}
        </div>
      </div>

      {filteredMedia.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredMedia.map((media) => (
            <div 
              key={media.id} 
              className="group bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-2xl transition-all duration-300 overflow-hidden cursor-pointer"
              onClick={() => onPlay(media)}
            >
              <div className="relative aspect-[4/3] overflow-hidden">
                <img
                  src={media.thumbnailUrl}
                  alt={media.title}
                  className="w-full h-full object-cover transform transition-transform group-hover:scale-110"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-red-900/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <div className="bg-white p-4 rounded-full text-red-700 shadow-xl transform scale-90 group-hover:scale-100 transition-all">
                    <Play className="h-6 w-6 fill-current" />
                  </div>
                </div>
                <div className="absolute top-2 right-2 bg-red-800/90 backdrop-blur-md text-white text-[10px] px-2 py-1 rounded-md font-bold">
                  {media.duration}
                </div>
                <div className="absolute bottom-3 left-3 bg-red-700 text-white text-[10px] uppercase tracking-widest px-2.5 py-1 rounded shadow-lg font-bold">
                  {media.category}
                </div>
              </div>

              <div className="p-5 space-y-4">
                <div className="space-y-1">
                  <h3 className="text-lg font-bold text-slate-900 group-hover:text-red-700 transition-colors line-clamp-1 font-serif">
                    {media.title}
                  </h3>
                  <div className="flex flex-col space-y-1 text-xs text-slate-500 font-bold">
                    <div className="flex items-center uppercase tracking-tight">
                      <User className="h-3 w-3 mr-2 text-red-600" />
                      {media.preacher}
                    </div>
                    <div className="flex items-center uppercase tracking-tight">
                      <Calendar className="h-3 w-3 mr-2 text-red-600" />
                      {new Date(media.datePreached).toLocaleDateString()}
                    </div>
                  </div>
                </div>

                <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                  <div className="flex items-center space-x-3 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                    <span>{media.playCount.toLocaleString()} Plays</span>
                    <span>•</span>
                    <span>{media.downloadCount.toLocaleString()} DLs</span>
                  </div>
                  <button
                    onClick={(e) => handleDownload(e, media)}
                    className="p-2 text-slate-400 hover:text-red-700 hover:bg-red-50 rounded-lg transition-all"
                  >
                    <Download className="h-5 w-5" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="py-32 text-center bg-white rounded-3xl border border-dashed border-red-200">
          <div className="max-w-xs mx-auto space-y-4">
            <div className="bg-red-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
              <Search className="h-10 w-10 text-red-200" />
            </div>
            <h3 className="text-xl font-bold text-slate-900 font-serif">No matches found</h3>
            <p className="text-slate-500">We couldn't find any media matching your search. Try different keywords.</p>
            <button
              onClick={() => { setSearchQuery(''); setSelectedCategory('All'); }}
              className="text-red-700 font-bold hover:underline"
            >
              Clear all filters
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Library;

import React from 'react';
import { Play, Pause, SkipBack, SkipForward, Volume2, Download, X } from 'lucide-react';
import { Media } from '../types';
import { db } from '../services/db';

interface AudioPlayerProps {
  media: Media | null;
  onClose: () => void;
}

const AudioPlayer: React.FC<AudioPlayerProps> = ({ media, onClose }) => {
  const [isPlaying, setIsPlaying] = React.useState(false);
  const [progress, setProgress] = React.useState(0);
  const [volume, setVolume] = React.useState(80);
  const audioRef = React.useRef<HTMLAudioElement | null>(null);

  React.useEffect(() => {
    if (media) {
      setIsPlaying(true);
      db.incrementPlay(media.id);
      if (audioRef.current) {
        audioRef.current.play();
      }
    }
  }, [media]);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) audioRef.current.pause();
      else audioRef.current.play();
      setIsPlaying(!isPlaying);
    }
  };

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      const p = (audioRef.current.currentTime / audioRef.current.duration) * 100;
      setProgress(p || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (audioRef.current) {
      const newTime = (parseFloat(e.target.value) / 100) * audioRef.current.duration;
      audioRef.current.currentTime = newTime;
      setProgress(parseFloat(e.target.value));
    }
  };

  const handleDownload = () => {
    if (media) {
      db.incrementDownload(media.id);
      const link = document.createElement('a');
      link.href = media.fileUrl;
      link.download = `${media.title}.mp3`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  if (!media) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 shadow-[0_-10px_40px_rgba(0,0,0,0.1)] z-[100] transform transition-transform duration-300">
      <audio
        ref={audioRef}
        src={media.fileUrl}
        onTimeUpdate={handleTimeUpdate}
        onEnded={() => setIsPlaying(false)}
      />

      <div className="max-w-7xl mx-auto px-4 py-4 flex flex-col md:flex-row items-center justify-between gap-4">
        {/* Media Info */}
        <div className="flex items-center space-x-4 w-full md:w-1/4">
          <img
            src={media.thumbnailUrl}
            alt={media.title}
            className="w-14 h-14 rounded-xl object-cover shadow-md border-2 border-red-50"
          />
          <div className="overflow-hidden">
            <h4 className="text-sm font-bold text-slate-900 truncate font-serif">{media.title}</h4>
            <p className="text-[10px] font-bold text-red-600 uppercase tracking-widest">{media.preacher}</p>
          </div>
          <button onClick={onClose} className="md:hidden ml-auto p-1 text-slate-400">
            <X className="h-5 w-5" />
          </button>
        </div>

        {/* Controls */}
        <div className="flex flex-col items-center w-full md:w-1/2 gap-2">
          <div className="flex items-center space-x-8">
            <button className="text-slate-400 hover:text-red-700 transition-colors">
              <SkipBack className="h-6 w-6" />
            </button>
            <button
              onClick={togglePlay}
              className="bg-red-700 text-white p-4 rounded-full hover:bg-red-800 transition-all shadow-xl shadow-red-200"
            >
              {isPlaying ? <Pause className="h-6 w-6 fill-current" /> : <Play className="h-6 w-6 fill-current ml-0.5" />}
            </button>
            <button className="text-slate-400 hover:text-red-700 transition-colors">
              <SkipForward className="h-6 w-6" />
            </button>
          </div>
          <div className="w-full flex items-center space-x-4">
            <span className="text-[10px] font-bold text-slate-400 w-10 text-right">
              {audioRef.current ? formatTime(audioRef.current.currentTime) : '0:00'}
            </span>
            <input
              type="range"
              min="0"
              max="100"
              step="0.1"
              value={progress}
              onChange={handleSeek}
              className="w-full h-1.5 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-red-700"
            />
            <span className="text-[10px] font-bold text-slate-400 w-10">
              {media.duration}
            </span>
          </div>
        </div>

        {/* Tools */}
        <div className="hidden md:flex items-center justify-end space-x-6 w-1/4">
          <div className="flex items-center space-x-3">
            <Volume2 className="h-4 w-4 text-slate-400" />
            <input
              type="range"
              min="0"
              max="100"
              value={volume}
              onChange={(e) => {
                const v = parseInt(e.target.value);
                setVolume(v);
                if (audioRef.current) audioRef.current.volume = v / 100;
              }}
              className="w-24 h-1 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-red-700"
            />
          </div>
          <button
            onClick={handleDownload}
            className="flex items-center space-x-2 text-xs font-bold text-red-700 hover:text-white bg-red-50 hover:bg-red-700 px-4 py-2 rounded-xl border border-red-100 transition-all shadow-sm"
          >
            <Download className="h-4 w-4" />
            <span>MP3</span>
          </button>
          <button onClick={onClose} className="p-1 text-slate-400 hover:text-red-700 transition-colors">
            <X className="h-6 w-6" />
          </button>
        </div>
      </div>
    </div>
  );
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

export default AudioPlayer;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, X, ImagePlus, FileImage, Play, Headphones, CloudUpload, User, Calendar, Download, Users, ShieldCheck, Mail, AlertCircle } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category, Admin } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [activeTab, setActiveTab] = React.useState<'library' | 'users'>('library');
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [adminList, setAdminList] = React.useState<Admin[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isAdminModalOpen, setIsAdminModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);

  // Audio Upload States
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);

  // Thumbnail Upload States
  const [isUploadingThumb, setIsUploadingThumb] = React.useState(false);

  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const [newAdminEmail, setNewAdminEmail] = React.useState('');

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
    setAdminList(db.getAdmins());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setIsUploadingThumb(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";
    if (!formData.datePreached) newErrors.datePreached = "A valid preaching date is required";
    if (!formData.description.trim()) newErrors.description = "A brief description helps members find content";
    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";
    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (newAdminEmail) {
      db.addAdmin(newAdminEmail);
      setAdminList(db.getAdmins());
      setNewAdminEmail('');
      setIsAdminModalOpen(false);
    }
  };

  const handleRemoveAdmin = (id: string) => {
    if (confirm('Are you sure you want to revoke this user\'s admin privileges?')) {
      db.removeAdmin(id);
      setAdminList(db.getAdmins());
    }
  };

  const handleGenerateAI = async () => {
    if (!formData.description) {
      setErrors(prev => ({ ...prev, description: "Enter a description first so AI can analyze it" }));
      return;
    }
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file (PNG/JPG)." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      setIsUploadingThumb(true);

      setTimeout(() => {
        const objectUrl = URL.createObjectURL(file);
        setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
        setIsUploadingThumb(false);
      }, 800);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Only MP3 files are accepted." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

