                            <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
                          </label>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Form Buttons */}
              <div className="mt-10 flex items-center space-x-4">
                <button
                  type="submit"
                  disabled={isUploadingFile || isUploadingThumb}
                  className="flex-grow py-4 bg-red-700 text-white font-bold rounded-2xl hover:bg-red-800 transition-all shadow-xl shadow-red-100 disabled:opacity-50"
