};

export default AdminDashboard;

import React from 'react';
import { Search, Filter, Play, Download, Calendar, User, SlidersHorizontal, History, X, Trash2 } from 'lucide-react';
import { db } from '../services/db';
import { Media, Category } from '../types';

interface LibraryProps {
  onPlay: (media: Media) => void;
}

const SEARCH_HISTORY_KEY = 'faithstream_recent_searches';
const MAX_HISTORY = 6;

const Library: React.FC<LibraryProps> = ({ onPlay }) => {
  const [allMedia, setAllMedia] = React.useState<Media[]>([]);
  const [filteredMedia, setFilteredMedia] = React.useState<Media[]>([]);
  const [searchQuery, setSearchQuery] = React.useState('');
  const [selectedCategory, setSelectedCategory] = React.useState<string>('All');
  const [recentSearches, setRecentSearches] = React.useState<string[]>([]);

  // Load initial data
  React.useEffect(() => {
    const data = db.getMedia();
    setAllMedia(data);
    setFilteredMedia(data);

    const savedHistory = localStorage.getItem(SEARCH_HISTORY_KEY);
    if (savedHistory) {
      try {
        setRecentSearches(JSON.parse(savedHistory));
      } catch (e) {
        setRecentSearches([]);
      }
    }
  }, []);

  // Filter and history update logic
  React.useEffect(() => {
    let result = allMedia;

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(m => 
        m.title.toLowerCase().includes(q) || 
        m.preacher.toLowerCase().includes(q) ||
        m.description?.toLowerCase().includes(q)
      );
    }

    if (selectedCategory !== 'All') {
      result = result.filter(m => m.category === selectedCategory);
    }

    setFilteredMedia(result);

    // Debounced history update
    const timeoutId = setTimeout(() => {
      const trimmed = searchQuery.trim();
      if (trimmed.length >= 3) {
        updateHistory(trimmed);
      }
    }, 1500);

    return () => clearTimeout(timeoutId);
  }, [searchQuery, selectedCategory, allMedia]);

  const updateHistory = (query: string) => {
    setRecentSearches(prev => {
      // Don't add if already at the top
      if (prev[0] === query) return prev;

      const filtered = prev.filter(s => s.toLowerCase() !== query.toLowerCase());
      const updated = [query, ...filtered].slice(0, MAX_HISTORY);
      localStorage.setItem(SEARCH_HISTORY_KEY, JSON.stringify(updated));
      return updated;
    });
  };

  const removeHistoryItem = (e: React.MouseEvent, itemToRemove: string) => {
    e.stopPropagation();
    setRecentSearches(prev => {
      const updated = prev.filter(item => item !== itemToRemove);
      localStorage.setItem(SEARCH_HISTORY_KEY, JSON.stringify(updated));
      return updated;
    });
  };

  const clearHistory = () => {
    setRecentSearches([]);
    localStorage.removeItem(SEARCH_HISTORY_KEY);
  };

  const handleDownload = (e: React.MouseEvent, media: Media) => {
    e.stopPropagation();
    db.incrementDownload(media.id);
    const link = document.createElement('a');
    link.href = media.fileUrl;
    link.download = `${media.title}.mp3`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
          <h1 className="text-4xl font-bold text-slate-900 font-serif">Message Library</h1>
          <p className="text-slate-500 text-lg">Browse our spiritual archives for your edification.</p>
        </div>

        <div className="flex flex-col gap-4 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="relative flex-grow sm:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
              <input
                type="text"
                placeholder="Search title, preacher..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-10 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-red-600 outline-none text-slate-900 font-bold shadow-sm placeholder:font-normal placeholder:text-slate-400"
              />
              {searchQuery && (
                <button 
                  onClick={() => setSearchQuery('')}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-red-700 p-1"
                >
                  <X className="h-4 w-4" />
                </button>
              )}
            </div>
            <div className="relative">
              <SlidersHorizontal className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-red-600 outline-none text-slate-900 font-bold"
              >
                <option value="All">All Categories</option>
                {Object.values(Category).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
              <Filter className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none" />
            </div>
          </div>

          {recentSearches.length > 0 && (
            <div className="flex flex-wrap items-center gap-2 animate-in fade-in slide-in-from-top-1">
              <div className="flex items-center text-slate-400 mr-1">
                <History className="h-3.5 w-3.5 mr-1" />
                <span className="text-[10px] font-bold uppercase tracking-widest">Recent:</span>
              </div>
              {recentSearches.map((term, idx) => (
                <div 
                  key={idx}
                  onClick={() => setSearchQuery(term)}
                  className="group flex items-center bg-red-50 hover:bg-red-100 text-red-700 text-[11px] font-bold rounded-full border border-red-100 transition-all shadow-sm cursor-pointer pl-3 pr-1.5 py-1"
                >
                  <span className="mr-2">{term}</span>
                  <button
                    onClick={(e) => removeHistoryItem(e, term)}
                    className="p-0.5 rounded-full hover:bg-red-200 text-red-400 hover:text-red-700 transition-colors"
                  >
                    <X className="h-2.5 w-2.5" />
                  </button>
                </div>
              ))}
              <button 
                onClick={clearHistory} 
                className="flex items-center space-x-1 px-2 py-1 text-slate-300 hover:text-red-600 transition-colors text-[10px] font-bold uppercase tracking-tighter"
                title="Clear all"
              >
                <Trash2 className="h-3 w-3" />
                <span>Clear</span>
              </button>
            </div>
          )}
        </div>
      </div>

      {filteredMedia.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredMedia.map((media) => (
            <div 
              key={media.id} 
              className="group bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-2xl transition-all duration-300 overflow-hidden cursor-pointer flex flex-col"
              onClick={() => onPlay(media)}
            >
              <div className="relative aspect-[4/3] overflow-hidden">
                <img
                  src={media.thumbnailUrl}
                  alt={media.title}
                  className="w-full h-full object-cover transform transition-transform group-hover:scale-110"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-red-900/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <div className="bg-white p-4 rounded-full text-red-700 shadow-xl transform scale-90 group-hover:scale-100 transition-all">
                    <Play className="h-6 w-6 fill-current" />
                  </div>
                </div>
                <div className="absolute top-2 right-2 bg-red-800/90 backdrop-blur-md text-white text-[10px] px-2 py-1 rounded-md font-bold">
                  {media.duration}
                </div>
                <div className="absolute bottom-3 left-3 bg-red-700 text-white text-[10px] uppercase tracking-widest px-2.5 py-1 rounded shadow-lg font-bold">
                  {media.category}
                </div>
              </div>

              <div className="p-5 space-y-4 flex-grow flex flex-col justify-between">
                <div className="space-y-1">
                  <h3 className="text-lg font-bold text-slate-900 group-hover:text-red-700 transition-colors line-clamp-1 font-serif">
                    {media.title}
                  </h3>
                  <div className="flex flex-col space-y-1 text-xs text-slate-500 font-bold">
                    <div className="flex items-center uppercase tracking-tight">
                      <User className="h-3 w-3 mr-2 text-red-600" />
                      {media.preacher}
                    </div>
                    <div className="flex items-center uppercase tracking-tight">
                      <Calendar className="h-3 w-3 mr-2 text-red-600" />
                      {new Date(media.datePreached).toLocaleDateString()}
                    </div>
                  </div>
                </div>

                <div className="pt-4 border-t border-slate-100 flex items-center justify-between mt-auto">
                  <div className="flex items-center space-x-3 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                    <span>{media.playCount.toLocaleString()} Plays</span>
                    <span>•</span>
                    <span>{media.downloadCount.toLocaleString()} DLs</span>
                  </div>
                  <button
                    onClick={(e) => handleDownload(e, media)}
                    className="p-2 text-slate-400 hover:text-red-700 hover:bg-red-50 rounded-lg transition-all"
                  >
                    <Download className="h-5 w-5" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="py-32 text-center bg-white rounded-3xl border border-dashed border-red-200">
          <div className="max-w-xs mx-auto space-y-4">
            <div className="bg-red-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
              <Search className="h-10 w-10 text-red-200" />
            </div>
            <h3 className="text-xl font-bold text-slate-900 font-serif">No matches found</h3>
            <p className="text-slate-500">We couldn't find any media matching your search. Try different keywords.</p>
            <button
              onClick={() => { setSearchQuery(''); setSelectedCategory('All'); }}
              className="text-red-700 font-bold hover:underline"
            >
              Clear all filters
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Library;

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, X, ImagePlus, FileImage, Play, Headphones, CloudUpload, User, Calendar, Download, Users, ShieldCheck, Mail, AlertCircle } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category, Admin } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [activeTab, setActiveTab] = React.useState<'library' | 'users'>('library');
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [adminList, setAdminList] = React.useState<Admin[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isAdminModalOpen, setIsAdminModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);

  // Audio Upload States
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);

  // Thumbnail Upload States
  const [isUploadingThumb, setIsUploadingThumb] = React.useState(false);

  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const [newAdminEmail, setNewAdminEmail] = React.useState('');

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
    setAdminList(db.getAdmins());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setIsUploadingThumb(false);
    setShowSuccess(false);
    setErrors({});
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";
    if (!formData.datePreached) newErrors.datePreached = "A valid preaching date is required";
    if (!formData.description.trim()) newErrors.description = "A brief description helps members find content";
    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";
    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (newAdminEmail) {
      db.addAdmin(newAdminEmail);
      setAdminList(db.getAdmins());
      setNewAdminEmail('');
      setIsAdminModalOpen(false);
    }
  };

  const handleRemoveAdmin = (id: string) => {
    if (confirm('Are you sure you want to revoke this user\'s admin privileges?')) {
      db.removeAdmin(id);
      setAdminList(db.getAdmins());
    }
  };

  const handleGenerateAI = async () => {
    if (!formData.description) {
      setErrors(prev => ({ ...prev, description: "Enter a description first so AI can analyze it" }));
      return;
    }
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file (PNG/JPG)." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      setIsUploadingThumb(true);

      setTimeout(() => {
        const objectUrl = URL.createObjectURL(file);
        setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
        setIsUploadingThumb(false);
      }, 800);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Only MP3 files are accepted." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900 font-serif">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1 uppercase text-xs font-bold tracking-widest">Winners Media Management Portal</p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => setIsAdminModalOpen(true)}
            className="flex items-center space-x-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-50 transition-all shadow-sm"
          >
            <Users className="h-4 w-4" />
            <span>Add Admin</span>
          </button>
          <button
            onClick={handleAddNew}
            className="flex items-center space-x-2 px-6 py-2 bg-red-700 text-white font-bold rounded-xl hover:bg-red-800 transition-all shadow-lg shadow-red-100"
          >
            <Plus className="h-5 w-5" />
            <span>New Message</span>
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex space-x-1 bg-slate-200/50 p-1.5 rounded-2xl w-fit">
        <button
          onClick={() => setActiveTab('library')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'library' ? 'bg-white text-red-700 shadow-md' : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          Message Library
        </button>
        <button
          onClick={() => setActiveTab('users')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'users' ? 'bg-white text-red-700 shadow-md' : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          Team Management
        </button>
      </div>

      {activeTab === 'library' ? (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[
              { label: 'Published Messages', value: mediaList.length, icon: Upload, color: 'bg-red-50 text-red-700' },
              { label: 'Spiritual Impact (Plays)', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-amber-50 text-amber-700' },
              { label: 'Resources Shared (DLs)', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-red-50 text-red-800' },
            ].map((stat) => (
              <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
                <div>
                  <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">{stat.label}</p>
                  <p className="text-3xl font-bold text-slate-900 mt-2">{stat.value}</p>
                </div>
                <div className={`${stat.color} p-4 rounded-2xl shadow-inner`}>
                  <stat.icon className="h-8 w-8" />
                </div>
              </div>
            ))}
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="px-6 py-4 border-b border-slate-100 bg-red-50/30">
              <h2 className="font-bold text-red-900 uppercase tracking-widest text-sm">Media Content Database</h2>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] border-b border-slate-100 bg-slate-50/50">
                    <th className="px-6 py-5">Message Details</th>
                    <th className="px-6 py-5">Preacher</th>
                    <th className="px-6 py-5">Date</th>
                    <th className="px-6 py-5">Engagement</th>
                    <th className="px-6 py-5 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100/50">
                  {mediaList.map((media) => (
                    <tr 
                      key={media.id} 
                      className="transition-all group even:bg-slate-50/40 hover:bg-red-50/40"
                    >
                      <td className="px-6 py-5">
                        <div className="flex items-center space-x-4">
                          <div className="relative w-14 h-14 flex-shrink-0 group-hover:scale-105 transition-transform duration-300">
                            <img src={media.thumbnailUrl} className="w-full h-full object-cover rounded-xl shadow-sm border border-slate-100" alt="" />
                            <button 
                              onClick={() => onPlay?.(media)}
                              className="absolute inset-0 bg-red-900/60 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded-xl transition-all duration-300"
                            >
                              <Play className="h-5 w-5 text-white fill-current transform scale-90 group-hover:scale-100" />
                            </button>
                          </div>
                          <div>
                            <div className="text-sm font-bold text-slate-900 line-clamp-1 font-serif group-hover:text-red-700 transition-colors">{media.title}</div>
                            <div className="text-[10px] font-extrabold text-red-600/80 uppercase tracking-[0.15em] mt-0.5">{media.category}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex items-center text-sm font-bold text-slate-700">
                          <User className="h-4 w-4 mr-2.5 text-red-700/40 group-hover:text-red-700/60" />
                          {media.preacher}
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex items-center text-sm text-slate-500 font-medium">
                          <Calendar className="h-4 w-4 mr-2.5 text-red-700/40 group-hover:text-red-700/60" />
                          {new Date(media.datePreached).toLocaleDateString()}
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex flex-col space-y-1.5">
                          <div className="flex items-center text-[10px] font-bold text-slate-400 group-hover:text-slate-600 transition-colors">
                            <Headphones className="h-3.5 w-3.5 mr-2 text-red-700/30 group-hover:text-red-700" />
                            {media.playCount.toLocaleString()} <span className="ml-1 opacity-50">PLAYS</span>
                          </div>
                          <div className="flex items-center text-[10px] font-bold text-slate-400 group-hover:text-slate-600 transition-colors">
                            <Download className="h-3.5 w-3.5 mr-2 text-amber-600/30 group-hover:text-amber-600" />
                            {media.downloadCount.toLocaleString()} <span className="ml-1 opacity-50">DLS</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-5 text-right">
                        <div className="flex items-center justify-end space-x-1">
                          <button 
                            onClick={() => handleEdit(media)}
                            className="p-2.5 text-slate-400 hover:text-red-700 hover:bg-red-50 rounded-xl transition-all active:scale-90"
                            title="Edit message"
                          >
                            <Edit3 className="h-4.5 w-4.5" />
                          </button>
                          <button 
                            onClick={() => handleDelete(media.id)}
                            className="p-2.5 text-slate-400 hover:text-red-900 hover:bg-red-50 rounded-xl transition-all active:scale-90"
                            title="Delete message"
                          >
                            <Trash2 className="h-4.5 w-4.5" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </>
      ) : (
        <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm max-w-4xl">
          <div className="px-6 py-4 border-b border-slate-100 bg-red-50/30 flex items-center justify-between">
            <h2 className="font-bold text-red-900 uppercase tracking-widest text-sm">Authorized Administrators</h2>
            <span className="text-xs font-bold text-red-700 bg-red-100 px-3 py-1 rounded-full">{adminList.length} Total</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] border-b border-slate-100 bg-slate-50/50">
                  <th className="px-6 py-5">Admin Email Address</th>
                  <th className="px-6 py-5">Access Level</th>
                  <th className="px-6 py-5 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100/50">
                {adminList.map((admin) => (
                  <tr 
                    key={admin.id} 
                    className="transition-all even:bg-slate-50/40 hover:bg-red-50/40"
                  >
                    <td className="px-6 py-5">
                      <div className="flex items-center text-sm font-bold text-slate-900 group">
                        <Mail className="h-4.5 w-4.5 mr-4 text-red-700/40 group-hover:text-red-700" />
                        {admin.email}
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <span className="inline-flex items-center px-3.5 py-1.5 rounded-full text-[10px] font-extrabold bg-amber-50 text-amber-800 border border-amber-100 uppercase tracking-widest shadow-sm">
                        <ShieldCheck className="h-3.5 w-3.5 mr-2" /> Full Access
                      </span>
                    </td>
                    <td className="px-6 py-5 text-right">
                      {adminList.length > 1 && (
                        <button 
                          onClick={() => handleRemoveAdmin(admin.id)}
                          className="p-2.5 text-slate-400 hover:text-red-700 hover:bg-red-50 rounded-xl transition-all active:scale-95"
