                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Audio Content (MP3) <span className="text-red-500">*</span></label>
                      <div className={`relative border-2 border-dashed rounded-2xl p-4 transition-all ${showSuccess ? 'border-green-200 bg-green-50' : 'border-red-100 hover:border-red-300 bg-red-50/20'}`}>
                        {isUploadingFile ? (
