import { Media, Category, Admin } from '../types';

const MEDIA_KEY = 'faithstream_media';
const ADMIN_KEY = 'faithstream_admins';

const DEFAULT_MEDIA: Media[] = [
  {
    id: '1',
    title: 'The Power of Grace',
    preacher: 'Pastor John Doe',
    category: Category.SERMON,
    description: 'An inspiring message about the transformative power of grace in our daily lives.',
    datePreached: '2023-10-15',
    fileUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3',
    thumbnailUrl: 'https://picsum.photos/seed/sermon1/800/600',
    duration: '45:20',
    playCount: 1250,
    downloadCount: 450,
    createdAt: new Date().toISOString()
  },
  {
    id: '2',
    title: 'Morning Worship Session',
    preacher: 'Faith Choir',
    category: Category.WORSHIP,
    description: 'A soul-stirring worship session to start your week with praise.',
    datePreached: '2023-11-01',
    fileUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3',
    thumbnailUrl: 'https://picsum.photos/seed/worship1/800/600',
    duration: '15:10',
    playCount: 3400,
    downloadCount: 890,
    createdAt: new Date().toISOString()
  }
];

const DEFAULT_ADMINS: Admin[] = [
  { id: 'admin-1', email: 'admin@church.com' }
];

export const db = {
  // Media Methods
  getMedia: (): Media[] => {
    const data = localStorage.getItem(MEDIA_KEY);
    if (!data) {
      localStorage.setItem(MEDIA_KEY, JSON.stringify(DEFAULT_MEDIA));
      return DEFAULT_MEDIA;
    }
    return JSON.parse(data);
  },

  saveMedia: (media: Media[]) => {
    localStorage.setItem(MEDIA_KEY, JSON.stringify(media));
  },

  addMedia: (item: Omit<Media, 'id' | 'playCount' | 'downloadCount' | 'createdAt'>) => {
    const current = db.getMedia();
    const newItem: Media = {
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      playCount: 0,
      downloadCount: 0,
      createdAt: new Date().toISOString()
    };
    db.saveMedia([newItem, ...current]);
    return newItem;
  },

  updateMedia: (id: string, updates: Partial<Media>) => {
    const current = db.getMedia();
    const updated = current.map(m => m.id === id ? { ...m, ...updates } : m);
    db.saveMedia(updated);
  },

  deleteMedia: (id: string) => {
    const current = db.getMedia();
    db.saveMedia(current.filter(m => m.id !== id));
  },

  incrementPlay: (id: string) => {
    const current = db.getMedia();
    const updated = current.map(m => m.id === id ? { ...m, playCount: m.playCount + 1 } : m);
    db.saveMedia(updated);
  },

  incrementDownload: (id: string) => {
    const current = db.getMedia();
    const updated = current.map(m => m.id === id ? { ...m, downloadCount: m.downloadCount + 1 } : m);
    db.saveMedia(updated);
  },

  // Admin Methods
  getAdmins: (): Admin[] => {
    const data = localStorage.getItem(ADMIN_KEY);
    if (!data) {
      localStorage.setItem(ADMIN_KEY, JSON.stringify(DEFAULT_ADMINS));
      return DEFAULT_ADMINS;
    }
    return JSON.parse(data);
  },

  addAdmin: (email: string) => {
    const admins = db.getAdmins();
    if (admins.find(a => a.email === email)) return;
    const newAdmin: Admin = {
      id: Math.random().toString(36).substr(2, 9),
      email
    };
    localStorage.setItem(ADMIN_KEY, JSON.stringify([...admins, newAdmin]));
  },

  updateAdmin: (id: string, email: string) => {
    const admins = db.getAdmins();
    const updated = admins.map(a => a.id === id ? { ...a, email } : a);
    localStorage.setItem(ADMIN_KEY, JSON.stringify(updated));
  },

  removeAdmin: (id: string) => {
    const admins = db.getAdmins();
    if (admins.length <= 1) return; // Prevent deleting the last admin
    localStorage.setItem(ADMIN_KEY, JSON.stringify(admins.filter(a => a.id !== id)));
  }
};

import React from 'react';
import { Plus, Trash2, Edit3, BarChart3, Upload, Loader2, Sparkles, CheckCircle, X, ImagePlus, FileImage, Play, Headphones, CloudUpload, User, Calendar, Download, Users, ShieldCheck, Mail, AlertCircle, Save } from 'lucide-react';
import { db } from '../services/db';
import { geminiService } from '../services/gemini';
import { Media, Category, Admin } from '../types';

interface AdminDashboardProps {
  onPlay?: (media: Media) => void;
}

interface FormErrors {
  title?: string;
  preacher?: string;
  category?: string;
  datePreached?: string;
  description?: string;
  fileUrl?: string;
  thumbnailUrl?: string;
}

const MAX_AUDIO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onPlay }) => {
  const [activeTab, setActiveTab] = React.useState<'library' | 'users'>('library');
  const [mediaList, setMediaList] = React.useState<Media[]>([]);
  const [adminList, setAdminList] = React.useState<Admin[]>([]);
  const [isModalOpen, setIsModalOpen] = React.useState(false);
  const [isAdminModalOpen, setIsAdminModalOpen] = React.useState(false);
  const [isGenerating, setIsGenerating] = React.useState(false);

  // Audio Upload States
  const [isUploadingFile, setIsUploadingFile] = React.useState(false);
  const [uploadProgress, setUploadProgress] = React.useState(0);
  const [showSuccess, setShowSuccess] = React.useState(false);

  // Thumbnail Upload States
  const [isUploadingThumb, setIsUploadingThumb] = React.useState(false);

  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [editingAdminId, setEditingAdminId] = React.useState<string | null>(null);
  const [errors, setErrors] = React.useState<FormErrors>({});

  const [adminEmailForm, setAdminEmailForm] = React.useState('');

  const initialFormState = {
    title: '',
    preacher: '',
    category: Category.SERMON,
    description: '',
    datePreached: new Date().toISOString().split('T')[0],
    fileUrl: '', 
    thumbnailUrl: '',
    duration: '40:00'
  };

  const [formData, setFormData] = React.useState(initialFormState);

  React.useEffect(() => {
    setMediaList(db.getMedia());
    setAdminList(db.getAdmins());
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setIsUploadingFile(false);
    setIsUploadingThumb(false);
    setShowSuccess(false);
    setErrors({});
  };

  const closeAdminModal = () => {
    setIsAdminModalOpen(false);
    setEditingAdminId(null);
    setAdminEmailForm('');
  };

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.title.trim()) newErrors.title = "A message title is required";
    if (!formData.preacher.trim()) newErrors.preacher = "The preacher/speaker name is required";
    if (!formData.datePreached) newErrors.datePreached = "A valid preaching date is required";
    if (!formData.description.trim()) newErrors.description = "A brief description helps members find content";
    if (!formData.fileUrl) newErrors.fileUrl = "Please upload an MP3 audio file";
    if (!formData.thumbnailUrl) newErrors.thumbnailUrl = "A thumbnail image is required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this media from the library?')) {
      db.deleteMedia(id);
      setMediaList(db.getMedia());
    }
  };

  const handleEdit = (media: Media) => {
    setEditingId(media.id);
    setFormData({
      title: media.title,
      preacher: media.preacher,
      category: media.category,
      description: media.description || '',
      datePreached: media.datePreached,
      fileUrl: media.fileUrl,
      thumbnailUrl: media.thumbnailUrl,
      duration: media.duration
    });
    setUploadProgress(100); 
    setShowSuccess(true);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAddNew = () => {
    setEditingId(null);
    setFormData(initialFormState);
    setUploadProgress(0);
    setShowSuccess(false);
    setIsModalOpen(true);
    setErrors({});
  };

  const handleAdminSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!adminEmailForm) return;

    if (editingAdminId) {
      db.updateAdmin(editingAdminId, adminEmailForm);
    } else {
      db.addAdmin(adminEmailForm);
    }

    setAdminList(db.getAdmins());
    closeAdminModal();
  };

  const handleEditAdmin = (admin: Admin) => {
    setEditingAdminId(admin.id);
    setAdminEmailForm(admin.email);
    setIsAdminModalOpen(true);
  };

  const handleRemoveAdmin = (id: string) => {
    if (confirm('Are you sure you want to revoke this user\'s admin privileges?')) {
      db.removeAdmin(id);
      setAdminList(db.getAdmins());
    }
  };

  const handleGenerateAI = async () => {
    if (!formData.description) {
      setErrors(prev => ({ ...prev, description: "Enter a description first so AI can analyze it" }));
      return;
    }
    setIsGenerating(true);
    const result = await geminiService.generateMediaMetadata(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        title: result.suggestedTitle
      }));
      setErrors(prev => ({ ...prev, title: undefined }));
    }
    setIsGenerating(false);
  };

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Please select a valid image file (PNG/JPG)." }));
        return;
      }
      if (file.size > MAX_IMAGE_SIZE) {
        setErrors(prev => ({ ...prev, thumbnailUrl: "Thumbnail exceeds 5MB limit." }));
        return;
      }

      setErrors(prev => ({ ...prev, thumbnailUrl: undefined }));
      setIsUploadingThumb(true);

      setTimeout(() => {
        const objectUrl = URL.createObjectURL(file);
        setFormData(prev => ({ ...prev, thumbnailUrl: objectUrl }));
        setIsUploadingThumb(false);
      }, 800);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setErrors(prev => ({ ...prev, fileUrl: undefined }));
      setShowSuccess(false);
      setUploadProgress(0);

      const isMp3 = file.type === 'audio/mpeg' || file.name.toLowerCase().endsWith('.mp3');
      if (!isMp3) {
        setErrors(prev => ({ ...prev, fileUrl: "Unsupported format. Only MP3 files are accepted." }));
        e.target.value = '';
        return;
      }

      if (file.size > MAX_AUDIO_SIZE) {
        setErrors(prev => ({ ...prev, fileUrl: "File too large. Maximum allowed size is 100MB." }));
        e.target.value = '';
        return;
      }

      setIsUploadingFile(true);

      let progress = 0;
      const interval = setInterval(() => {
        progress += Math.random() * 15;
        if (progress >= 100) {
          progress = 100;
          clearInterval(interval);

          const objectUrl = URL.createObjectURL(file);
          setFormData(prev => ({
            ...prev,
            fileUrl: objectUrl
          }));
          setIsUploadingFile(false);
          setUploadProgress(100);
          setShowSuccess(true);
        } else {
          setUploadProgress(Math.floor(progress));
        }
      }, 100);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    if (editingId) {
      db.updateMedia(editingId, formData);
    } else {
      db.addMedia(formData);
    }

    setMediaList(db.getMedia());
    closeModal();
  };

  const totalPlays = mediaList.reduce((acc, m) => acc + m.playCount, 0);
  const totalDownloads = mediaList.reduce((acc, m) => acc + m.downloadCount, 0);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold text-slate-900 font-serif">Admin Dashboard</h1>
          <p className="text-slate-500 mt-1 uppercase text-xs font-bold tracking-widest">Winners Media Management Portal</p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => { setEditingAdminId(null); setAdminEmailForm(''); setIsAdminModalOpen(true); }}
            className="flex items-center space-x-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-50 transition-all shadow-sm"
          >
            <Users className="h-4 w-4 text-red-700" />
            <span>Add Admin</span>
          </button>
          <button
            onClick={handleAddNew}
            className="flex items-center space-x-2 px-6 py-2 bg-red-700 text-white font-bold rounded-xl hover:bg-red-800 transition-all shadow-lg shadow-red-100"
          >
            <Plus className="h-5 w-5" />
            <span>New Message</span>
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex space-x-1 bg-slate-200/50 p-1.5 rounded-2xl w-fit">
        <button
          onClick={() => setActiveTab('library')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'library' ? 'bg-white text-red-700 shadow-md' : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          Message Library
        </button>
        <button
          onClick={() => setActiveTab('users')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'users' ? 'bg-white text-red-700 shadow-md' : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          Team Management
        </button>
      </div>

      {activeTab === 'library' ? (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[
              { label: 'Published Messages', value: mediaList.length, icon: Upload, color: 'bg-red-50 text-red-700' },
              { label: 'Spiritual Impact (Plays)', value: totalPlays.toLocaleString(), icon: BarChart3, color: 'bg-amber-50 text-amber-700' },
              { label: 'Resources Shared (DLs)', value: totalDownloads.toLocaleString(), icon: CheckCircle, color: 'bg-red-50 text-red-800' },
            ].map((stat) => (
              <div key={stat.label} className="bg-white p-8 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
                <div>
                  <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">{stat.label}</p>
                  <p className="text-3xl font-bold text-slate-900 mt-2">{stat.value}</p>
                </div>
                <div className={`${stat.color} p-4 rounded-2xl shadow-inner`}>
                  <stat.icon className="h-8 w-8" />
                </div>
              </div>
            ))}
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="px-6 py-4 border-b border-slate-100 bg-red-50/30">
              <h2 className="font-bold text-red-900 uppercase tracking-widest text-sm">Media Content Database</h2>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
